import { prisma } from '@/lib/prisma';
import { notFound } from 'next/navigation';
import { Metadata } from 'next';
import { Language } from '@prisma/client';
import Link from 'next/link';
import { CalendarDays, Sparkles } from 'lucide-react';
import { resolvePageBySlug, resolveLandingPageBySlug, createLocalizedUrl, buildHreflangAlternates } from '@/lib/page-resolver';

// Page bile┼şenleri art─▒k _pages/ klas├Âr├╝nde (underscore prefix = Next.js route DE─Ş─░L)
import ServicesPageContent from '../_pages/ServicesPage';
import GalleryPageContent from '../_pages/GalleryPage';
import ContactPageContent from '../_pages/ContactPage';
import PortfolioPageContent from '../_pages/PortfolioPage';
import BookingPageContent from '../_pages/BookingPage';
import BlogPageContent from '../_pages/BlogPage';

type Props = {
  params: Promise<{ locale: string; landingSlug: string }>;
};

// ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
// SEO METADATA
// ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const resolvedParams = await params;
  const { locale, landingSlug } = resolvedParams;
  const languageEnum = locale.toUpperCase() as Language;

  try {
    // 1. PageTranslation'da slug ara
    const pageResult = await resolvePageBySlug(landingSlug, languageEnum);

    if (pageResult) {
      const { translation, pageGroup, allTranslations } = pageResult;

      // Sistem sayfalar─▒ i├ğin orijinal sayfan─▒n metadata's─▒n─▒ delegele
      if (pageGroup === 'SERVICES' || pageGroup === 'CONTACT' || pageGroup === 'GALLERY' || 
          pageGroup === 'PORTFOLIO' || pageGroup === 'BOOKING' || pageGroup === 'BLOG') {
        // Bu sayfalar─▒n kendi generateMetadata'lar─▒ var, ama biz daha iyi bir metadata ├╝retebiliriz
        const title = translation.seoTitle || `${translation.title} | Nails & Lashes Studio`;
        const desc = translation.seoDesc || translation.title;
        const hreflang = buildHreflangAlternates(allTranslations);
        const currentUrl = createLocalizedUrl(locale, landingSlug);

        return {
          title,
          description: desc,
          alternates: {
            canonical: translation.canonical || `https://nailslashesstudio.com${currentUrl}`,
            languages: hreflang
          },
          openGraph: {
            title: translation.ogTitle || title,
            description: translation.ogDesc || desc,
            images: [{ url: translation.ogImage || translation.headerImage || 'https://nailslashesstudio.com/images/luxury_salon_hero.png' }],
          },
          twitter: {
            card: 'summary_large_image',
            title: translation.ogTitle || title,
            description: translation.ogDesc || desc,
          },
          robots: {
            index: translation.index ?? true,
            follow: translation.index ?? true,
          }
        };
      }

      // Normal CMS sayfalar─▒
      const title = translation.seoTitle || `${translation.title} | Nails & Lashes Studio`;
      const desc = translation.seoDesc || translation.title;
      const hreflang = buildHreflangAlternates(allTranslations);
      const currentUrl = createLocalizedUrl(locale, landingSlug);

      return {
        title,
        description: desc,
        alternates: {
          canonical: translation.canonical || `https://nailslashesstudio.com${currentUrl}`,
          languages: hreflang
        },
        openGraph: {
          title: translation.ogTitle || title,
          description: translation.ogDesc || desc,
          images: translation.ogImage ? [{ url: translation.ogImage }] : [{ url: 'https://nailslashesstudio.com/images/luxury_salon_hero.png' }],
        },
        twitter: {
          card: 'summary_large_image',
          title: translation.ogTitle || title,
          description: translation.ogDesc || desc,
        },
        robots: {
          index: translation.index ?? true,
          follow: translation.index ?? true,
        }
      };
    }

    // 2. LandingPageTranslation'da ara
    const landingResult = await resolveLandingPageBySlug(landingSlug, languageEnum);

    if (landingResult) {
      const { translation, allTranslations } = landingResult;
      const title = translation.seoTitle || `${translation.title} | Nails & Lashes Studio`;
      const desc = translation.seoDesc || translation.title;
      const hreflang = buildHreflangAlternates(allTranslations);
      const currentUrl = createLocalizedUrl(locale, landingSlug);

      return {
        title,
        description: desc,
        alternates: {
          canonical: translation.canonical || `https://nailslashesstudio.com${currentUrl}`,
          languages: hreflang
        },
        openGraph: {
          title: translation.ogTitle || title,
          description: translation.ogDesc || desc,
          images: translation.ogImage ? [{ url: translation.ogImage }] : [{ url: 'https://nailslashesstudio.com/images/luxury_salon_hero.png' }],
        },
        robots: {
          index: translation.index ?? true,
          follow: translation.index ?? true,
        }
      };
    }
  } catch (error) {
    console.error("Slug metadata hatas─▒:", error);
  }

  return { title: 'Sayfa Bulunamad─▒' };
}

// ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
// PAGE RENDER
// ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
export default async function DynamicSlugPage({ params }: Props) {
  const resolvedParams = await params;
  const { locale, landingSlug } = resolvedParams;
  const languageEnum = locale.toUpperCase() as Language;

  try {
    // 1. PageTranslation'da slug + language ara
    const pageResult = await resolvePageBySlug(landingSlug, languageEnum);

    if (pageResult) {
      const { translation, pageGroup } = pageResult;

      // ÔöÇÔöÇÔöÇ HEADLESS ROUTER: pageGroup'a g├Âre do─şru bile┼şeni render et ÔöÇÔöÇÔöÇ
      // Hangi slug ile gelinirse gelinsin, pageGroup "SERVICES" ise
      // Hizmetler sayfas─▒n─▒n tam tasar─▒m─▒ render edilir.

      if (pageGroup === 'SERVICES') {
        return <ServicesPageContent params={Promise.resolve({ locale })} />;
      }
      if (pageGroup === 'CONTACT') {
        return <ContactPageContent params={Promise.resolve({ locale })} />;
      }
      if (pageGroup === 'GALLERY') {
        return <GalleryPageContent params={Promise.resolve({ locale })} />;
      }
      if (pageGroup === 'PORTFOLIO') {
        return <PortfolioPageContent params={Promise.resolve({ locale })} />;
      }
      if (pageGroup === 'BOOKING') {
        return <BookingPageContent params={Promise.resolve({ locale })} />;
      }
      if (pageGroup === 'BLOG') {
        return <BlogPageContent params={Promise.resolve({ locale })} />;
      }

      // ÔöÇÔöÇÔöÇ ABOUT, LEGAL ve di─şer CMS sayfalar─▒ genel ┼şablonla render edilir ÔöÇÔöÇÔöÇ
      return renderCmsPage(translation, locale, landingSlug, true);
    }

    // 2. LandingPageTranslation'da ara
    const landingResult = await resolveLandingPageBySlug(landingSlug, languageEnum);

    if (landingResult) {
      return renderCmsPage(landingResult.translation, locale, landingSlug, false);
    }

  } catch (error) {
    console.error("Slug sayfa ├ğekme hatas─▒:", error);
  }

  // Hi├ğbir e┼şle┼şme bulunamad─▒
  notFound();
}

// ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
// CMS / Landing Page Render Helper
// ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
function renderCmsPage(translation: any, locale: string, slug: string, isCmsPage: boolean) {
  const titleText = translation.title || translation.h1Title || '';

  const webpageSchema = isCmsPage ? {
    "@context": "https://schema.org",
    "@type": "WebPage",
    "name": titleText,
    "url": `https://nailslashesstudio.com${createLocalizedUrl(locale, slug)}`,
    "description": translation.seoDesc || titleText
  } : null;

  const businessSchema = !isCmsPage ? {
    "@context": "https://schema.org",
    "@type": "BeautySalon",
    "name": `Nails & Lashes Studio - ${titleText}`,
    "image": "https://nailslashesstudio.com/images/luxury_salon_hero.png",
    "url": `https://nailslashesstudio.com${createLocalizedUrl(locale, slug)}`,
    "description": translation.seoDesc || titleText,
    "address": {
      "@type": "PostalAddress",
      "addressLocality": "Antalya",
      "addressCountry": "TR"
    }
  } : null;

  const breadcrumbSchema = {
    "@context": "https://schema.org",
    "@type": "BreadcrumbList",
    "itemListElement": [
      {
        "@type": "ListItem",
        "position": 1,
        "name": locale === 'tr' ? 'Ana Sayfa' : 'Home',
        "item": `https://nailslashesstudio.com/${locale === 'tr' ? '' : locale}`
      },
      {
        "@type": "ListItem",
        "position": 2,
        "name": titleText,
        "item": `https://nailslashesstudio.com${createLocalizedUrl(locale, slug)}`
      }
    ]
  };

  return (
    <main className="min-h-screen pt-32 pb-24 relative overflow-hidden bg-[#faf8f7]">
      {businessSchema && (
        <script
          type="application/ld+json"
          dangerouslySetInnerHTML={{ __html: JSON.stringify(businessSchema) }}
        />
      )}
      {webpageSchema && (
        <script
          type="application/ld+json"
          dangerouslySetInnerHTML={{ __html: JSON.stringify(webpageSchema) }}
        />
      )}
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(breadcrumbSchema) }}
      />

      <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-[var(--color-rose-400)]/5 rounded-full blur-3xl -z-10 animate-glow"></div>

      <div className="max-w-4xl mx-auto px-6 z-10">
        <div className="bg-white border border-[var(--color-rose-100)] rounded-[2.5rem] p-8 md:p-16 shadow-sm relative overflow-hidden">
          {!isCmsPage && (
            <div className="absolute top-0 left-0 right-0 h-2 bg-gradient-to-r from-[var(--color-rose-300)] via-[var(--color-rose-500)] to-[var(--color-rose-300)]"></div>
          )}

          <div className="mb-10 text-center">
            {isCmsPage ? (
              <span className="inline-flex items-center gap-1.5 px-3 py-1 bg-gray-50 text-gray-500 rounded-full text-[10px] font-bold uppercase tracking-widest mb-4">
                Kurumsal Bilgi
              </span>
            ) : (
              <span className="inline-flex items-center gap-1.5 px-3 py-1 bg-[var(--color-rose-50)] text-[var(--color-rose-700)] rounded-full text-[10px] font-bold uppercase tracking-widest mb-4">
                <Sparkles size={12} /> ├ûzel Kampanya & Hizmet
              </span>
            )}
            <h1 className="text-3xl md:text-5xl font-serif italic font-bold text-gray-950 leading-tight mb-4">
              {titleText}
            </h1>
            <div className="w-16 h-1 bg-[var(--color-rose-200)] mx-auto rounded-full"></div>
          </div>

          <article className="prose max-w-none text-gray-700 leading-relaxed text-sm md:text-base mb-12 prose-headings:font-serif prose-headings:text-gray-900 prose-a:text-[var(--color-rose-600)] hover:prose-a:text-[var(--color-rose-800)] prose-img:rounded-3xl">
            <div 
              className="whitespace-pre-line text-left"
              dangerouslySetInnerHTML={{ __html: translation.content }} 
            />
          </article>

          {!isCmsPage && (
            <div className="mt-12 p-8 rounded-3xl bg-[var(--color-light-200)] border border-[var(--color-primary-300)]/30 text-center space-y-6">
              <h3 className="text-xl font-serif font-bold text-gray-950">
                {locale === 'tr' ? 'Bu Hizmet ─░├ğin Hemen Randevunuzu Al─▒n' : 'Book Your Appointment Now'}
              </h3>
              <p className="text-gray-500 text-sm max-w-md mx-auto leading-relaxed">
                {locale === 'tr' 
                  ? '─░stedi─şiniz ┼şube, tarih, uzman ve saati se├ğerek 2 dakikada kolayca randevunuzu olu┼şturabilirsiniz.'
                  : 'Select your preferred branch, date, staff, and time slot to easily book in just 2 minutes.'}
              </p>
              <div className="flex justify-center">
                <Link
                  href={`/${locale}/booking`}
                  className="px-10 py-4 bg-gray-950 hover:bg-black text-white text-xs font-bold uppercase tracking-widest rounded-full transition-all shadow-md hover:-translate-y-0.5 flex items-center gap-2 cursor-pointer"
                >
                  <CalendarDays size={16} />
                  {locale === 'tr' ? 'HEMEN RANDEVU AL' : 'BOOK AN APPOINTMENT'}
                </Link>
              </div>
            </div>
          )}
        </div>
      </div>
    </main>
  );
}

import { prisma } from '@/lib/prisma';
import { Language } from '@prisma/client';
import GalleryClient from '@/components/layout/GalleryClient';

export default async function GalleryPageContent({ params }: { params: Promise<{ locale: string }> }) {
  const resolvedParams = await params;
  const locale = resolvedParams.locale;
  const languageEnum = locale.toUpperCase() as Language;

  // Veritaban─▒ndan galeri kategorileri ve foto─şraflar─▒ ├ğek
  let dbCategories: any[] = [];
  let dbItems: any[] = [];

  try {
    const rawCategories = await prisma.galleryCategory.findMany({
      where: { isActive: true, isDeleted: false },
      include: {
        translations: { where: { language: languageEnum } },
        _count: { select: { items: { where: { isActive: true, isDeleted: false } } } }
      },
      orderBy: { order: 'asc' }
    });
    dbCategories = rawCategories.filter(c => c._count.items > 0 || true); // t├╝m├╝n├╝ g├Âster

    const rawItems = await prisma.galleryItem.findMany({
      where: { isActive: true, isDeleted: false },
      include: {
        translations: { where: { language: languageEnum } },
        category: { include: { translations: { where: { language: languageEnum } } } }
      },
      orderBy: { order: 'asc' }
    });
    dbItems = rawItems;
  } catch (error) {
    console.error('Galeri veri ├ğekme hatas─▒:', error);
  }

  // Eski GalleryImage fallback (GalleryItem bo┼şsa)
  if (dbItems.length === 0) {
    try {
      const oldImages = await prisma.galleryImage.findMany({ where: { isActive: true }, orderBy: { order: 'asc' } });
      const mediaImages = await prisma.mediaItem.findMany({ where: { mimeType: { startsWith: 'image/' } }, orderBy: { createdAt: 'desc' } });

      const legacyItems = oldImages.map(img => ({
        id: img.id, imageUrl: img.url, categoryId: null, category: null,
        translations: [{ language: languageEnum, title: img.altText || 'Nails & Lashes Studio', altText: img.altText || '', description: '' }]
      }));

      mediaImages.forEach(med => {
        if (!legacyItems.some(i => i.imageUrl === med.url)) {
          legacyItems.push({
            id: med.id, imageUrl: med.url, categoryId: null, category: null,
            translations: [{ language: languageEnum, title: med.title || 'Nails & Lashes Studio', altText: med.altText || '', description: '' }]
          });
        }
      });

      dbItems = legacyItems;
    } catch (_e) { /* ignore */ }
  }

  // Fallback g├Ârseller (hi├ğ veri yoksa)
  if (dbItems.length === 0) {
    dbItems = [
      { id: 'f1', imageUrl: '/images/nail_art_1.png', categoryId: null, category: null, translations: [{ language: languageEnum, title: 'Nail Art', altText: 'Nail Art', description: '' }] },
      { id: 'f2', imageUrl: '/images/nail_art_2.png', categoryId: null, category: null, translations: [{ language: languageEnum, title: 'Manik├╝r', altText: 'Manicure', description: '' }] },
      { id: 'f3', imageUrl: '/images/lash_art_1.png', categoryId: null, category: null, translations: [{ language: languageEnum, title: '─░pek Kirpik', altText: 'Lashes', description: '' }] },
      { id: 'f4', imageUrl: '/images/lash_art_2.png', categoryId: null, category: null, translations: [{ language: languageEnum, title: 'Kirpik Lifting', altText: 'Lash Lift', description: '' }] },
      { id: 'f5', imageUrl: '/images/luxury_salon_hero.png', categoryId: null, category: null, translations: [{ language: languageEnum, title: 'St├╝dyo', altText: 'Studio', description: '' }] },
    ];
  }

  // Kategori + foto─şraf verilerini client'a uygun formata d├Ân├╝┼şt├╝r
  const publicCategories = dbCategories.map(c => ({
    id: c.id,
    name: c.translations?.[0]?.name || 'Kategori',
    slug: c.translations?.[0]?.slug || '',
    itemCount: c._count?.items || 0,
  }));

  const publicImages = dbItems.map((item: any) => ({
    id: item.id,
    url: item.imageUrl,
    alt: item.translations?.[0]?.altText || item.translations?.[0]?.title || 'Nails & Lashes Studio',
    title: item.translations?.[0]?.title || '',
    description: item.translations?.[0]?.description || '',
    categoryId: item.categoryId || null,
    categoryName: item.category?.translations?.[0]?.name || null,
  }));

  // Page content
  const pageContent = await prisma.pageTranslation.findFirst({
    where: { language: languageEnum, page: { pageGroup: 'GALLERY', isActive: true, isDeleted: false } }
  }).catch(() => null);

  const heroTitle = pageContent?.h1Title || (locale === 'tr' ? 'G├Ârsel Galeri' : locale === 'de' ? 'Bildergalerie' : locale === 'ru' ? 'ºñº¥ªéº¥º│º░º╗ºÁªÇºÁªÅ' : 'Visual Gallery');
  const introText = pageContent?.introText || (locale === 'tr'
    ? 'T─▒rnak sanat─▒, protez t─▒rnak, kirpik ve ka┼ş uygulamalar─▒m─▒z─▒n ger├ğek ve taze foto─şraflar─▒yla ├ğal─▒┼şmalar─▒m─▒z─▒ inceleyin.'
    : locale === 'de' ? 'Entdecken Sie unsere neuesten Arbeiten mit echten Fotos von Nagelkunst und Wimpernverl├ñngerungen.'
    : locale === 'ru' ? 'ºşº¥ªüº╝º¥ªéªÇº©ªéºÁ º¢º░ªêº© º┐º¥ªüº╗ºÁº┤º¢º©ºÁ ªÇº░º▒º¥ªéªï: º┤º©ºÀº░º╣º¢ º¢º¥º│ªéºÁº╣, º¢º░ªÇº░ªëº©º▓º░º¢º©ºÁ ªÇºÁªüº¢º©ªå º© º╝º¢º¥º│º¥ºÁ º┤ªÇªâº│º¥ºÁ.'
    : 'Explore our latest work with real photos of nail art, acrylic nails, and eyelash extensions.');

  const tagText = locale === 'tr' ? 'Sanat ve Estetik' : locale === 'de' ? 'Kunst & ├ästhetik' : locale === 'ru' ? 'ºİªüº║ªâªüªüªéº▓º¥ º© º¡ªüªéºÁªéº©º║º░' : 'Art & Aesthetics';

  return (
    <main className="min-h-screen pt-32 pb-24 relative overflow-hidden bg-[#faf8f7]">
      <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-[var(--color-rose-400)]/5 rounded-full blur-3xl -z-10 animate-glow"></div>
      <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-[var(--color-rose-300)]/5 rounded-full blur-3xl -z-10 animate-glow" style={{ animationDelay: '1.5s' }}></div>
      <div className="max-w-7xl mx-auto px-6 z-10">
        <div className="text-center mb-16">
          <span className="text-[var(--color-rose-600)] text-xs font-bold uppercase tracking-widest block mb-3">{tagText}</span>
          <h1 className="text-4xl md:text-5xl font-serif italic font-bold text-gray-950 mb-4">{heroTitle}</h1>
          <p className="text-gray-500 max-w-2xl mx-auto text-sm md:text-base leading-relaxed">{introText}</p>
        </div>
        <GalleryClient images={publicImages} categories={publicCategories} locale={locale} />
      </div>
    </main>
  );
}

import Image from 'next/image';
import { prisma } from '@/lib/prisma';
import { notFound } from 'next/navigation';
import { Metadata } from 'next';
import { Language } from '@prisma/client';
import Link from 'next/link';
import { ArrowLeft, Calendar, User, HelpCircle, Sparkles, Scissors, Clock } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';

type Props = {
  params: Promise<{ locale: string; categorySlug: string; postSlug: string }>;
};

// Dinamik SEO Metadata Olu┼şturma
export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const resolvedParams = await params;
  const { locale, categorySlug, postSlug } = resolvedParams;
  const languageEnum = locale.toUpperCase() as Language;

  const translation = await prisma.blogPostTranslation.findFirst({
    where: {
      slug: postSlug,
      language: languageEnum,
      blogPost: {
        isDeleted: false,
        isActive: true,
      }
    }
  });

  if (!translation) {
    return { title: 'Makale Bulunamad─▒' };
  }

  const title = translation.seoTitle || `${translation.title} | Nails & Lashes Studio`;
  const desc = translation.seoDesc || translation.excerpt || translation.content.slice(0, 160);

  return {
    title,
    description: desc,
