// TOPLU SLOT OLU┼ŞTURMA
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ

export async function createBulkSlots(
  locationId: string,
  staffId: string | null,
  dateStr: string,
  slots: { time: string; capacity: number; isBlocked?: boolean }[]
) {
  try {
    const dateObj = new Date(dateStr + 'T00:00:00');
    let created = 0;
    let updated = 0;

    for (const slot of slots) {
      const existing = await prisma.appointmentSlot.findFirst({
        where: { locationId, staffId: staffId || null, date: dateObj, time: slot.time },
      });

      if (existing) {
        await prisma.appointmentSlot.update({
          where: { id: existing.id },
          data: { capacity: slot.capacity, isBlocked: slot.isBlocked || false },
        });
        updated++;
      } else {
        await prisma.appointmentSlot.create({
          data: {
            locationId, staffId: staffId || null, date: dateObj,
            time: slot.time, capacity: slot.capacity, isBlocked: slot.isBlocked || false,
          },
        });
        created++;
      }
    }

    revalidatePath('/admin/availability');
    await logAction('Toplu Slot Olu┼şturma', `┼Şube: ${locationId}, Tarih: ${dateStr}, Olu┼şturulan: ${created}, G├╝ncellenen: ${updated}`);
    return { success: true, created, updated };
  } catch (error: any) {
    return { success: false, error: 'Toplu slot olu┼şturulurken hata olu┼ştu.' };
  }
}

// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
// HAFTALIK ┼ŞABLON
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ

export async function applyWeeklyTemplate(
  locationId: string,
  staffId: string | null,
  startDateStr: string,
  weekCount: number,
  template: { dayOfWeek: number; slots: { time: string; capacity: number; isBlocked?: boolean }[] }[]
) {
  try {
    const startDate = new Date(startDateStr + 'T00:00:00');
    let totalCreated = 0;
    let totalUpdated = 0;

    for (let week = 0; week < weekCount; week++) {
      for (const dayTemplate of template) {
        // Tarih hesapla
        const date = new Date(startDate);
        date.setDate(startDate.getDate() + (week * 7) + dayTemplate.dayOfWeek - startDate.getDay());

        if (date < startDate) continue; // Ge├ğmi┼ş tarih atlama

        const dateStr = date.toISOString().split('T')[0];
        const result = await createBulkSlots(locationId, staffId, dateStr, dayTemplate.slots);

        if (result.success) {
          totalCreated += result.created || 0;
          totalUpdated += result.updated || 0;
        }
      }
    }

    await logAction('Haftal─▒k ┼Şablon Uyguland─▒', `┼Şube: ${locationId}, ${weekCount} hafta, Olu┼şturulan: ${totalCreated}, G├╝ncellenen: ${totalUpdated}`);
    return { success: true, created: totalCreated, updated: totalUpdated };
  } catch (error: any) {
    return { success: false, error: 'Haftal─▒k ┼şablon uygulan─▒rken hata olu┼ştu.' };
  }
}

