// ADM─░N DASHBOARD VER─░S─░
// ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ

export async function getAvailabilityDashboard(locationId: string, dateStr: string, staffId?: string) {
  try {
    const dateObj = new Date(dateStr + 'T00:00:00');
    const dayOfWeek = dateObj.getDay();

    // Paralel sorgular
    const [
      locationHours,
      holidays,
      appointmentSlots,
      timeBlocks,
      appointments,
      staffList,
    ] = await Promise.all([
      prisma.workingHours.findMany({ where: { locationId }, orderBy: { dayOfWeek: 'asc' } }),
      prisma.holiday.findMany({ where: { locationId }, orderBy: { date: 'asc' } }),
      prisma.appointmentSlot.findMany({
        where: { locationId, date: dateObj, isActive: true },
        include: { staff: true },
      }),
      prisma.timeBlock.findMany({
        where: { locationId, date: dateObj, ...(staffId ? { staffId } : {}) },
        include: { staff: true },
      }),
      prisma.appointment.findMany({
        where: {
          locationId, date: dateObj,
          status: { in: [ApptStatus.PENDING, ApptStatus.CONFIRMED, ApptStatus.RESCHEDULED] },
          ...(staffId ? { staffId } : {}),
        },
        include: { staff: true, service: { include: { translations: { where: { language: 'TR' } } } } },
      }),
      prisma.staff.findMany({
        where: { locationId, isActive: true, isDeleted: false },
        include: {
          workingHours: { where: { dayOfWeek } },
          leaves: { where: { date: dateObj } },
          services: { include: { service: { include: { translations: { where: { language: 'TR' } } } } } },
        },
        orderBy: { name: 'asc' },
      }),
    ]);

    return {
      success: true,
      data: {
        locationHours: JSON.parse(JSON.stringify(locationHours)),
        holidays: JSON.parse(JSON.stringify(holidays)),
        appointmentSlots: JSON.parse(JSON.stringify(appointmentSlots)),
        timeBlocks: JSON.parse(JSON.stringify(timeBlocks)),
        appointments: JSON.parse(JSON.stringify(appointments)),
        staffList: JSON.parse(JSON.stringify(staffList)),
        dayOfWeek,
      },
    };
  } catch (error: any) {
    console.error('Dashboard verisi al─▒n─▒rken hata:', error);
    return { success: false, error: 'Dashboard verisi al─▒namad─▒.' };
  }
}

"use server";

import { prisma } from '@/lib/prisma';
import { ApptSource, StaffPreference } from '@prisma/client';
import { sendBookingEmail } from '@/lib/email';
import { getAvailableTimeSlots } from './availability';
import { getCurrentCustomer } from './customerAuth';
import { logAction } from './audit';

export async function createBooking(data: {
  serviceId: string;
  locationId: string;
  staffId: string;
  dateStr: string;
  startTime: string;
  name: string;
  email: string;
  phone: string;
  notes?: string;
  locale?: string;
}) {
  try {
    if (!data.locationId || !data.serviceId || !data.staffId || !data.dateStr || !data.startTime) {
      return { success: false, error: 'Eksik randevu bilgileri!' };
    }

    if (!data.name || !data.name.trim()) {
      return { success: false, error: 'Ad Soyad alan─▒ zorunludur!' };
    }

    if (!data.email || !data.email.trim()) {
      return { success: false, error: 'E-posta alan─▒ zorunludur!' };
    }

    const upperLocale = (data.locale || 'tr').toUpperCase();
    const resolvedLanguage = ['TR', 'EN', 'RU', 'DE'].includes(upperLocale) ? upperLocale : 'TR';
    const dateStr = data.dateStr;
    const dateObj = new Date(dateStr + 'T00:00:00');
    const dayOfWeek = dateObj.getDay();

    // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ 10 MADDEL─░K SERVER-SIDE KONTROL Z─░NC─░R─░ ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ

    // 1. ┼Şube aktif mi?
    const location = await prisma.location.findUnique({ where: { id: data.locationId } });
    if (!location || !location.isActive || location.isDeleted) {
      return { success: false, error: 'Se├ğilen ┼şube aktif de─şil.' };
    }

    // 2. Hizmet aktif mi?
    const service = await prisma.service.findUnique({
      where: { id: data.serviceId },
      include: { translations: { where: { language: resolvedLanguage as any } } }
    });
    if (!service || service.isDeleted || !service.isActive) {
      return { success: false, error: 'Hizmet bulunamad─▒ veya pasif.' };
    }

    // 3. Hizmet bu ┼şubede aktif mi? (LocationService kontrol├╝)
    const locationService = await prisma.locationService.findUnique({
      where: { locationId_serviceId: { locationId: data.locationId, serviceId: data.serviceId } }
    });
    if (!locationService) {
      return { success: false, error: 'Bu hizmet se├ğilen ┼şubede verilmemektedir.' };
    }

    // 4. Personel bu ┼şubede ├ğal─▒┼ş─▒yor mu? (Belirli personel se├ğildiyse)
    if (data.staffId !== 'ANY') {
      const staff = await prisma.staff.findUnique({ where: { id: data.staffId } });
      if (!staff || !staff.isActive || staff.isDeleted) {
        return { success: false, error: 'Se├ğilen personel aktif de─şil.' };
      }
      if (staff.locationId !== data.locationId) {
        return { success: false, error: 'Se├ğilen personel bu ┼şubede ├ğal─▒┼şm─▒yor.' };
      }

      // 5. Personel bu hizmeti verebiliyor mu? (StaffService kontrol├╝)
      const staffService = await prisma.staffService.findUnique({
        where: { staffId_serviceId: { staffId: data.staffId, serviceId: data.serviceId } }
      });
      // Fallback: StaffService atamas─▒ yoksa t├╝m hizmetleri verebilir
      const anyStaffService = await prisma.staffService.count({ where: { staffId: data.staffId } });
      if (anyStaffService > 0 && !staffService) {
        return { success: false, error: 'Se├ğilen personel bu hizmeti veremiyor.' };
      }

      // 6. Personel izinde mi?
      const staffLeave = await prisma.staffLeave.findFirst({
        where: { staffId: data.staffId, date: dateObj, isFullDay: true }
      });
      if (staffLeave) {
        return { success: false, error: 'Se├ğilen personel bu tarihte izinlidir.' };
      }
    }

    // 7. ┼Şube tatili var m─▒?
    const holiday = await prisma.holiday.findFirst({
      where: { locationId: data.locationId, date: dateObj }
    });
    if (holiday) {
      return { success: false, error: `┼Şube bu tarihte kapal─▒d─▒r: ${holiday.description || 'Tatil g├╝n├╝'}` };
    }

    // 8. ┼Şube ├ğal─▒┼şma saati kontrol├╝
    const shopHours = await prisma.workingHours.findFirst({
      where: { locationId: data.locationId, dayOfWeek }
    });
    if (shopHours && shopHours.isClosed) {
      return { success: false, error: '┼Şube bu g├╝n kapal─▒d─▒r.' };
    }

    // 9. Hizmet s├╝resi slot aral─▒─ş─▒na uyuyor mu?
    const [startH, startM] = data.startTime.split(':').map(Number);
    const startMinutes = startH * 60 + startM;
    const endMinutes = startMinutes + service.duration;
    const shopCloseMin = shopHours ? parseInt(shopHours.closeTime.split(':')[0]) * 60 + parseInt(shopHours.closeTime.split(':')[1]) : 19 * 60;
    if (endMinutes > shopCloseMin) {
      return { success: false, error: 'Hizmet s├╝resi ┼şube kapan─▒┼ş saatini a┼ş─▒yor.' };
    }

    // 10. TimeBlock kontrol├╝ (belirli personel veya ┼şube geneli)
    const timeBlockCheck = await prisma.timeBlock.findFirst({
      where: {
        locationId: data.locationId,
        date: dateObj,
        OR: [
          { staffId: data.staffId !== 'ANY' ? data.staffId : undefined },
          { staffId: null },
        ],
      }
    });
    if (timeBlockCheck) {
      const tbStart = parseInt(timeBlockCheck.startTime.split(':')[0]) * 60 + parseInt(timeBlockCheck.startTime.split(':')[1]);
      const tbEnd = parseInt(timeBlockCheck.endTime.split(':')[0]) * 60 + parseInt(timeBlockCheck.endTime.split(':')[1]);
      if (startMinutes < tbEnd && endMinutes > tbStart) {
        return { success: false, error: `Bu saat aral─▒─ş─▒ blokeli: ${timeBlockCheck.reason}` };
      }
    }

    // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ M├£SAITLIK KONTROL├£ ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ

    const availability = await getAvailableTimeSlots(
      data.locationId,
      data.serviceId,
      dateStr,
      data.staffId
    );

    if (!availability.success || !availability.slots?.includes(data.startTime)) {
      return {
        success: false,
        error: 'Se├ğti─şiniz tarih veya saat art─▒k m├╝sait de─şil. L├╝tfen ba┼şka bir saat se├ğin.',
      };
    }

    // 3. ├çal─▒┼şan Belirleme (E─şer ANY/Fark etmez se├ğildiyse m├╝sait olan ilk personeli atayal─▒m)
    let assignedStaffId: string | null = data.staffId === 'ANY' ? null : data.staffId;

    if (data.staffId === 'ANY') {
      // Bu hizmeti verebilen o ┼şubedeki aktif personelleri bul
      const staffList = await prisma.staff.findMany({
        where: {
          locationId: data.locationId,
          isActive: true,
          isDeleted: false,
          services: {
            some: {
              serviceId: data.serviceId,
            },
          },
        },
      });

      // M├╝sait olan ilkini tespit et
      for (const staff of staffList) {
        const staffAvail = await getAvailableTimeSlots(
          data.locationId,
          data.serviceId,
          dateStr,
          staff.id
        );
        if (staffAvail.success && staffAvail.slots?.includes(data.startTime)) {
          assignedStaffId = staff.id;
          break;
        }
      }

      if (!assignedStaffId) {
        return {
          success: false,
          error: 'Se├ğti─şiniz saatte uygun personel bulunamad─▒. L├╝tfen ba┼şka bir saat se├ğin.',
        };
      }
    }

    // 4. Biti┼ş saatini hesapla (s├╝re ekleme)
    const [hours, minutes] = data.startTime.split(':').map(Number);
    const totalMinutes = hours * 60 + minutes + service.duration;
    const endHours = Math.floor(totalMinutes / 60);
    const endMins = totalMinutes % 60;
    const endTime = `${endHours.toString().padStart(2, '0')}:${endMins.toString().padStart(2, '0')}`;

    // Aktif m├╝┼şteri oturumunu al
    const customer = await getCurrentCustomer();

    // 5. Veritaban─▒na Randevuyu Ekle
    const appointment = await prisma.appointment.create({
      data: {
        serviceId: service.id,
        locationId: data.locationId,
        staffId: assignedStaffId,
        customerId: customer ? customer.id : null,
        date: dateObj,
        startTime: data.startTime,
        endTime: endTime,
        customerName: data.name,
        customerEmail: data.email,
        customerPhone: data.phone,
        notes: data.notes || null,
        priceAtBooking: service.price,
        durationAtBooking: service.duration,
        staffPreference: data.staffId === 'ANY' ? StaffPreference.ANY : StaffPreference.SELECTED,
        source: ApptSource.WEBSITE,
      }
    });

    // 5.1. AppointmentSlot tablosunda bookedCount alan─▒n─▒ art─▒r
    const existingSlot = await prisma.appointmentSlot.findFirst({
      where: {
        locationId: data.locationId,
        staffId: assignedStaffId || null,
        date: dateObj,
        time: data.startTime
      }
    });

    if (existingSlot) {
      await prisma.appointmentSlot.update({
        where: { id: existingSlot.id },
        data: {
          bookedCount: { increment: 1 }
        }
      });
    } else {
      await prisma.appointmentSlot.create({
        data: {
          locationId: data.locationId,
          staffId: assignedStaffId || null,
          date: dateObj,
          time: data.startTime,
          capacity: 1,
          bookedCount: 1
        }
      });
    }

    // 6. E-posta bildirimini g├Ânder
    if (data.email) {
      try {
        await sendBookingEmail(
          data.email,
          data.name,
          service.translations[0]?.name || 'Randevu',
          dateObj,
          data.startTime,
          resolvedLanguage
        );
      } catch (err) {
        console.error("E-posta g├Ânderim hatas─▒ (randevu ba┼şar─▒yla kaydedildi):", err);
      }
    }

    return { success: true, appointmentId: appointment.id };
  } catch (error) {
    console.error("Randevu olu┼şturma hatas─▒:", error);
    return { success: false, error: 'Randevu olu┼şturulurken bir hata olu┼ştu.' };
  }
}

export async function cancelAppointment(appointmentId: string) {
  try {
    const customer = await getCurrentCustomer();
    if (!customer) {
      return { success: false, error: 'L├╝tfen ├Ânce giri┼ş yap─▒n!' };
    }

    const appointment = await prisma.appointment.findUnique({
      where: { id: appointmentId },
      include: { service: true }
    });

    if (!appointment) {
      return { success: false, error: 'Randevu bulunamad─▒!' };
    }

    if (appointment.customerId !== customer.id) {
      return { success: false, error: 'Bu randevuyu iptal etme yetkiniz yok!' };
    }

    if (appointment.status === 'CANCELLED') {
      return { success: false, error: 'Bu randevu zaten iptal edilmi┼ş.' };
    }

    // ─░ptal limit saati kontrol├╝
    const cancelLimitSetting = await prisma.setting.findUnique({
      where: { key_language: { key: 'cancellation_limit_hours', language: 'TR' } }
    });

    const limitHours = cancelLimitSetting ? parseInt(cancelLimitSetting.value) : 24;

    const appointmentTimeStr = appointment.date.toISOString().split('T')[0] + 'T' + appointment.startTime + ':00';
    const appointmentDate = new Date(appointmentTimeStr);
    const now = new Date();

    const diffMs = appointmentDate.getTime() - now.getTime();
    const diffHours = diffMs / (1000 * 60 * 60);

    if (diffHours < limitHours) {
      return { 
        success: false, 
        error: `Randevunuza ${limitHours} saatten az zaman kald─▒─ş─▒ i├ğin online iptal i┼şlemi ger├ğekle┼ştiremezsiniz. L├╝tfen ┼şube ile ileti┼şime ge├ğin.` 
      };
    }

    // Randevuyu iptal et
    const updatedAppt = await prisma.appointment.update({
      where: { id: appointmentId },
      data: { status: 'CANCELLED' }
    });

    // Durum ge├ğmi┼şine ekle
    await prisma.appointmentStatusHistory.create({
      data: {
        appointmentId,
        status: 'CANCELLED',
        notes: 'M├╝┼şteri taraf─▒ndan online iptal edildi.'
      }
    });

    // AppointmentSlot tablosunda bookedCount alan─▒n─▒ azalt
    if (appointment.locationId) {
      const slot = await prisma.appointmentSlot.findFirst({
        where: {
          locationId: appointment.locationId,
          staffId: appointment.staffId || null,
          date: appointment.date,
          time: appointment.startTime
        }
      });

      if (slot && slot.bookedCount > 0) {
        await prisma.appointmentSlot.update({
          where: { id: slot.id },
          data: {
            bookedCount: { decrement: 1 }
          }
        });
      }
    }

    await logAction('M├╝┼şteri Randevu ─░ptal Etti', `ID: ${customer.id}, Randevu ID: ${appointmentId}`);

    return { success: true };
  } catch (error: any) {
    console.error('Randevu iptal hatas─▒:', error);
    return { success: false, error: 'Randevu iptal edilirken bir hata olu┼ştu.' };
  }
}

/**
 * M├╝┼şteri randevusunu yeni tarih/saate erteler.
 * Eski randevu RESCHEDULED stat├╝s├╝ne al─▒n─▒r, yeni tarih/saat atan─▒r.
 */
export async function rescheduleAppointment(
  appointmentId: string,
  newDateStr: string,
  newStartTime: string
) {
  try {
    const customer = await getCurrentCustomer();
    if (!customer) {
      return { success: false, error: 'L├╝tfen ├Ânce giri┼ş yap─▒n!' };
    }

    const appointment = await prisma.appointment.findUnique({
      where: { id: appointmentId },
      include: { service: true }
    });

    if (!appointment) {
      return { success: false, error: 'Randevu bulunamad─▒!' };
    }

    if (appointment.customerId !== customer.id) {
      return { success: false, error: 'Bu randevuyu de─şi┼ştirme yetkiniz yok!' };
    }

    if (appointment.status === 'CANCELLED' || appointment.status === 'COMPLETED') {
      return { success: false, error: '─░ptal edilmi┼ş veya tamamlanm─▒┼ş randevular de─şi┼ştirilemez.' };
    }

    // De─şi┼şiklik limiti kontrol├╝ (randevuya 24 saatten az kald─▒ysa engellensin)
    const cancelLimitSetting = await prisma.setting.findUnique({
      where: { key_language: { key: 'cancellation_limit_hours', language: 'TR' } }
    });
    const limitHours = cancelLimitSetting ? parseInt(cancelLimitSetting.value) : 24;

    const appointmentTimeStr = appointment.date.toISOString().split('T')[0] + 'T' + appointment.startTime + ':00';
    const appointmentDate = new Date(appointmentTimeStr);
    const now = new Date();
    const diffHours = (appointmentDate.getTime() - now.getTime()) / (1000 * 60 * 60);

    if (diffHours < limitHours) {
      return { 
        success: false, 
        error: `Randevunuza ${limitHours} saatten az zaman kald─▒─ş─▒ i├ğin online de─şi┼şiklik yap─▒lamaz. L├╝tfen ┼şube ile ileti┼şime ge├ğin.` 
      };
    }

    // Yeni tarih/saat m├╝sait mi kontrol et
    const staffId = appointment.staffId || 'ANY';
    const newDateObj = new Date(newDateStr + 'T00:00:00');

    const availability = await getAvailableTimeSlots(
      appointment.locationId || '',
      appointment.serviceId,
      newDateStr,
      staffId
    );

    if (!availability.success || !availability.slots?.includes(newStartTime)) {
      return { success: false, error: 'Se├ğti─şiniz yeni tarih/saat m├╝sait de─şil. L├╝tfen ba┼şka bir saat se├ğin.' };
    }

    // Biti┼ş saatini hesapla
    const duration = appointment.service.duration;
    const [hours, minutes] = newStartTime.split(':').map(Number);
    const totalMinutes = hours * 60 + minutes + duration;
    const endHours = Math.floor(totalMinutes / 60);
    const endMinutes = totalMinutes % 60;
    const newEndTime = `${endHours.toString().padStart(2, '0')}:${endMinutes.toString().padStart(2, '0')}`;

    // Eski slot'un bookedCount'unu azalt
    if (appointment.locationId) {
      const oldSlot = await prisma.appointmentSlot.findFirst({
        where: {
          locationId: appointment.locationId,
          staffId: appointment.staffId || null,
          date: appointment.date,
          time: appointment.startTime
        }
      });
      if (oldSlot && oldSlot.bookedCount > 0) {
        await prisma.appointmentSlot.update({
          where: { id: oldSlot.id },
          data: { bookedCount: { decrement: 1 } }
        });
      }
    }

    // Randevuyu g├╝ncelle
    await prisma.appointment.update({
      where: { id: appointmentId },
      data: {
        date: newDateObj,
        startTime: newStartTime,
        endTime: newEndTime,
        status: 'RESCHEDULED'
      }
    });

    // Durum ge├ğmi┼şine ekle
    await prisma.appointmentStatusHistory.create({
      data: {
        appointmentId,
        status: 'RESCHEDULED',
        notes: `M├╝┼şteri taraf─▒ndan online ertelendi. Yeni tarih: ${newDateStr} ${newStartTime}`
      }
    });

    // Yeni slot'un bookedCount'unu art─▒r
    if (appointment.locationId) {
      const existingSlot = await prisma.appointmentSlot.findFirst({
        where: {
          locationId: appointment.locationId,
          staffId: appointment.staffId || null,
          date: newDateObj,
          time: newStartTime
        }
      });

      if (existingSlot) {
        await prisma.appointmentSlot.update({
          where: { id: existingSlot.id },
          data: { bookedCount: { increment: 1 } }
        });
      } else {
        await prisma.appointmentSlot.create({
          data: {
            locationId: appointment.locationId,
            staffId: appointment.staffId || null,
            date: newDateObj,
            time: newStartTime,
            capacity: 1,
            bookedCount: 1
          }
        });
      }
    }

    await logAction('M├╝┼şteri Randevu Erteledi', `ID: ${customer.id}, Randevu: ${appointmentId}, Yeni: ${newDateStr} ${newStartTime}`);

    return { success: true };
  } catch (error: any) {
    console.error('Randevu erteleme hatas─▒:', error);
    return { success: false, error: 'Randevu ertelenirken bir hata olu┼ştu.' };
  }
}

"use server";

import { prisma } from '@/lib/prisma';
import { cookies } from 'next/headers';
import { revalidatePath } from 'next/cache';
import { hashPassword, verifyPassword, encryptSession, decryptSession } from '@/lib/auth-helpers';
import { LoginType, Language } from '@prisma/client';
import { logAction } from './audit';

/**
 * Yeni m├╝┼şteri kayd─▒ olu┼şturur.
 */
export async function registerCustomer(formData: FormData) {
  const name = formData.get('name') as string;
  const email = formData.get('email') as string;
  const phone = formData.get('phone') as string || null;
  const password = formData.get('password') as string;
  const passwordConfirm = formData.get('passwordConfirm') as string;
  const kvkkConsent = formData.get('kvkkConsent') === 'true';
  const newsletterConsent = formData.get('newsletterConsent') === 'true';
  const locale = (formData.get('locale') as string || 'tr').toLowerCase();

  if (!name || !email || !password) {
    return { success: false, error: 'Ad soyad, e-posta ve ┼şifre alanlar─▒ zorunludur!' };
  }

  if (password !== passwordConfirm) {
    return { success: false, error: '┼Şifreler uyu┼şmuyor!' };
  }

  if (!kvkkConsent) {
    return { success: false, error: 'KVKK ayd─▒nlatma metnini onaylaman─▒z gerekmektedir!' };
  }

  try {
    // E-posta m├╝kerrerlik kontrol├╝
    const existingUser = await prisma.user.findUnique({
      where: { email }
    });

    if (existingUser) {
      if (existingUser.loginType === LoginType.GOOGLE) {
        return { success: false, error: 'Bu e-posta adresi ile daha ├Ânce Google hesab─▒n─▒zla giri┼ş yapm─▒┼şt─▒n─▒z. L├╝tfen "Google ile Devam Et" butonunu kullanarak giri┼ş yap─▒n.' };
      }
      if (existingUser.loginType === LoginType.APPLE) {
        return { success: false, error: 'Bu e-posta adresi ile daha ├Ânce Apple hesab─▒n─▒zla giri┼ş yapm─▒┼şt─▒n─▒z. L├╝tfen "Apple ile Devam Et" butonunu kullanarak giri┼ş yap─▒n.' };
      }
      return { success: false, error: 'Bu e-posta adresiyle kay─▒tl─▒ bir hesap zaten mevcut. Giri┼ş yapmay─▒ deneyin veya ┼şifrenizi s─▒f─▒rlay─▒n.' };
    }

    const hashedPassword = hashPassword(password);

    // Kullan─▒c─▒y─▒ veritaban─▒nda olu┼ştur
    const newUser = await prisma.user.create({
      data: {
        name,
        email,
        phone,
        password: hashedPassword,
        loginType: LoginType.MANUAL,
        marketingConsent: newsletterConsent
      }
    });

    // E─şer b├╝ltene abone olmak istediyse, Subscriber tablosuna da kaydet
    if (newsletterConsent) {
      const languageEnum = locale.toUpperCase() as Language;
      await prisma.subscriber.create({
        data: {
          email,
          language: languageEnum,
          marketingConsent: true,
          userId: newUser.id,
          isActive: true
        }
      });
    }

    // HTTP-Only ├çerez Set Etme
    const cookieStore = await cookies();
    cookieStore.set('customer_token', encryptSession({ userId: newUser.id }), {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      maxAge: 60 * 60 * 24 * 30, // 30 g├╝n
      path: '/'
    });

    await logAction('M├╝┼şteri Kaydoldu', `ID: ${newUser.id}, ─░sim: ${name}, E-Posta: ${email}`);

    return { success: true, data: { id: newUser.id, name: newUser.name, email: newUser.email } };
  } catch (error: any) {
    console.error('M├╝┼şteri kay─▒t hatas─▒:', error);
    return { success: false, error: 'Kay─▒t i┼şlemi s─▒ras─▒nda bir hata olu┼ştu.' };
  }
}

/**
 * Manuel m├╝┼şteri giri┼şi yapar.
 */
export async function loginCustomer(formData: FormData) {
  const email = formData.get('email') as string;
  const password = formData.get('password') as string;

  if (!email || !password) {
    return { success: false, error: 'E-posta ve ┼şifre zorunludur!' };
  }

  try {
    const user = await prisma.user.findUnique({
      where: { email }
    });

    if (!user) {
      return { success: false, error: 'Bu e-posta adresiyle kay─▒tl─▒ bir hesap bulunamad─▒!' };
    }

    if (user.loginType === LoginType.GOOGLE) {
      return { success: false, error: 'Bu hesap Google ile olu┼şturulmu┼ş. L├╝tfen "Google ile Devam Et" butonunu kullan─▒n.' };
    }

    if (user.loginType === LoginType.APPLE) {
      return { success: false, error: 'Bu hesap Apple ile olu┼şturulmu┼ş. L├╝tfen "Apple ile Devam Et" butonunu kullan─▒n.' };
    }

    if (!user.password) {
      return { success: false, error: 'Bu hesapta ┼şifre tan─▒mlanmam─▒┼ş. L├╝tfen sosyal giri┼ş butonlar─▒n─▒ kullan─▒n.' };
    }

    const isMatch = verifyPassword(password, user.password);
    if (!isMatch) {
      return { success: false, error: 'Ge├ğersiz ┼şifre! L├╝tfen tekrar deneyin.' };
    }

    // HTTP-Only ├çerez Set Etme
    const cookieStore = await cookies();
    cookieStore.set('customer_token', encryptSession({ userId: user.id }), {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      maxAge: 60 * 60 * 24 * 30, // 30 g├╝n
      path: '/'
    });

    await logAction('M├╝┼şteri Giri┼ş Yapt─▒', `ID: ${user.id}, ─░sim: ${user.name}`);

    return { success: true, data: { id: user.id, name: user.name, email: user.email } };
  } catch (error: any) {
    console.error('M├╝┼şteri giri┼ş hatas─▒:', error);
    return { success: false, error: 'Giri┼ş yap─▒l─▒rken bir hata olu┼ştu.' };
  }
}

/**
 * Giri┼ş yapm─▒┼ş olan m├╝┼şterinin oturumunu kapat─▒r.
 */
export async function logoutCustomer() {
  const cookieStore = await cookies();
  cookieStore.delete('customer_token');
  return { success: true };
}

/**
 * Mevcut giri┼ş yapm─▒┼ş olan m├╝┼şterinin bilgilerini ve randevular─▒n─▒ ├ğerezden ├ğ├Âzer.
 */
export async function getCurrentCustomer() {
  try {
    const cookieStore = await cookies();
    const token = cookieStore.get('customer_token');
    if (!token) return null;

    const session = decryptSession(token.value);
    if (!session || !session.userId) return null;

    const user = await prisma.user.findUnique({
      where: { id: session.userId },
      include: {
        appointments: {
          include: {
            service: {
              include: {
                translations: true
              }
            },
            staff: true
          },
          orderBy: {
            date: 'desc'
          }
        },
        subscriber: true
      }
    });

    if (!user) return null;

    return {
      id: user.id,
      name: user.name,
      email: user.email,
      phone: user.phone,
      loginType: user.loginType,
      hasPassword: !!user.password,
      marketingConsent: user.marketingConsent,
      appointments: user.appointments.map(appt => ({
        id: appt.id,
        serviceName: appt.service.translations[0]?.name || 'Hizmet',
        staffName: appt.staff?.name || 'Uzman Belirtilmedi',
        date: appt.date.toISOString().split('T')[0],
        startTime: appt.startTime,
        endTime: appt.endTime,
        status: appt.status,
        price: appt.priceAtBooking.toString(),
        locationId: appt.locationId,
        serviceId: appt.serviceId,
        staffId: appt.staffId
      })),
      subscriberActive: user.subscriber?.isActive || false
    };
  } catch (error) {
    console.error('M├╝┼şteri ├ğ├Âz├╝mlenemedi:', error);
    return null;
  }
}

/**
 * Google/Apple ile giri┼ş yapm─▒┼ş m├╝┼şteriye manuel ┼şifre ekler.
 */
export async function addPasswordToSocialAccount(password: string) {
  try {
    const cookieStore = await cookies();
    const token = cookieStore.get('customer_token');
    if (!token) return { success: false, error: 'Oturum bulunamad─▒!' };

    const session = decryptSession(token.value);
    if (!session || !session.userId) return { success: false, error: 'Oturum bulunamad─▒!' };

    const hashedPassword = hashPassword(password);

    await prisma.user.update({
      where: { id: session.userId },
      data: {
        password: hashedPassword
      }
    });

    await logAction('M├╝┼şteri ┼Şifre Ekledi', `User ID: ${session.userId}`);
    return { success: true };
  } catch (error: any) {
    console.error('┼Şifre ekleme hatas─▒:', error);
    return { success: false, error: '┼Şifre eklenirken bir hata olu┼ştu.' };
  }
}

/**
 * M├╝┼şteri e-b├╝lten veya pazarlama iznini g├╝nceller.
 */
export async function updateCustomerMarketing(newsletterConsent: boolean, locale: string) {
  try {
    const cookieStore = await cookies();
    const token = cookieStore.get('customer_token');
    if (!token) return { success: false, error: 'Oturum bulunamad─▒!' };

    const session = decryptSession(token.value);
    if (!session || !session.userId) return { success: false, error: 'Oturum bulunamad─▒!' };

    const user = await prisma.user.findUnique({
      where: { id: session.userId },
      include: { subscriber: true }
    });

    if (!user) return { success: false, error: 'Kullan─▒c─▒ bulunamad─▒!' };

    // 1. User tablosunda g├╝ncelle
    await prisma.user.update({
      where: { id: session.userId },
      data: {
        marketingConsent: newsletterConsent
      }
    });

    // 2. Subscriber tablosunda g├╝ncelle veya ekle/├ğ─▒kar
    if (user.subscriber) {
      await prisma.subscriber.update({
        where: { id: user.subscriber.id },
        data: {
          isActive: newsletterConsent,
          marketingConsent: newsletterConsent,
          unsubscribedAt: newsletterConsent ? null : new Date()
        }
      });
    } else if (newsletterConsent && user.email) {
      const languageEnum = locale.toUpperCase() as Language;
      await prisma.subscriber.create({
        data: {
          email: user.email,
          language: languageEnum,
          marketingConsent: true,
          userId: user.id,
          isActive: true
        }
      });
    }

    await logAction('M├╝┼şteri Pazarlama ─░zni G├╝ncellendi', `ID: ${user.id}, ─░zin: ${newsletterConsent}`);
    return { success: true };
  } catch (error: any) {
    console.error('Pazarlama izni g├╝ncelleme hatas─▒:', error);
    return { success: false, error: 'Ayarlar g├╝ncellenirken hata olu┼ştu.' };
  }
}

export async function saveCookieConsent(necessary: boolean, analytics: boolean, marketing: boolean) {
  try {
    const cookieStore = await cookies();
    const token = cookieStore.get('customer_token');
    if (!token) return { success: false, error: 'Oturum bulunamad─▒!' };

    const session = decryptSession(token.value);
    if (!session || !session.userId) return { success: false, error: 'Oturum bulunamad─▒!' };

    const consentId = `consent_${session.userId}`;

    await prisma.cookieConsent.upsert({
      where: { userId: session.userId },
      update: {
        necessary,
        analytics,
        marketing
      },
      create: {
        userId: session.userId,
        consentId,
        necessary,
        analytics,
        marketing
      }
    });

    return { success: true };
  } catch (error) {
    console.error('├çerez izni kaydetme hatas─▒:', error);
    return { success: false, error: '├çerez tercihleri kaydedilemedi.' };
  }
}

