'use client';

import { useState } from 'react';
import { createTransaction } from '@/app/actions/transaction';
import { 
  TrendingUp, 
  TrendingDown, 
  Plus, 
  DollarSign, 
  Calendar, 
  User, 
  FileText,
  CreditCard,
  Wallet,
  Landmark,
  X,
  Sparkles,
  Users,
  MapPin
} from 'lucide-react';

type TransactionItem = {
  id: string;
  type: 'INCOME' | 'EXPENSE';
  amount: string;
  paymentMethod: 'CASH' | 'CARD' | 'TRANSFER';
  date: string;
  description: string | null;
  locationId: string | null;
  locationName: string;
  category: {
    name: string;
  };
  staff: {
    name: string;
  } | null;
};

type StaffItem = {
  id: string;
  name: string;
};

type StaffPayout = {
  staffId: string;
  name: string;
  appointmentCount: number;
  totalRevenue: number;
  commissionEarned: number;
};

type LocationItem = {
  id: string;
  name: string;
};

type Props = {
  transactions: TransactionItem[];
  staffList: StaffItem[];
  staffPayouts: StaffPayout[];
  locations: LocationItem[];
  };

export default function AccountingClient({ transactions, staffList, staffPayouts, locations }: Props) {
  const [modalOpen, setModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedLocationId, setSelectedLocationId] = useState<string>('ALL');

  // Filtrelenmi┼ş ─░┼şlemler
  const filteredTransactions = transactions.filter((t) => 
    selectedLocationId === 'ALL' || t.locationId === selectedLocationId
  );

  // Gelir & Gider Hesaplamalar─▒ (Filtrelenmi┼ş verilere g├Âre)
  const totalIncome = filteredTransactions
    .filter(t => t.type === 'INCOME')
    .reduce((sum, t) => sum + parseFloat(t.amount), 0);

  const totalExpense = filteredTransactions
    .filter(t => t.type === 'EXPENSE')
    .reduce((sum, t) => sum + parseFloat(t.amount), 0);

  const netProfit = totalIncome - totalExpense;

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const formData = new FormData(e.currentTarget);
    const categoryName = formData.get('categoryName') as string;
    const type = formData.get('type') as 'INCOME' | 'EXPENSE';
    const amountStr = formData.get('amount') as string;
    const paymentMethod = formData.get('paymentMethod') as 'CASH' | 'CARD' | 'TRANSFER';
    const description = formData.get('description') as string;
    const staffId = formData.get('staffId') as string;
    const locationId = formData.get('locationId') as string;

    const amount = parseFloat(amountStr);

    if (isNaN(amount) || amount <= 0) {
      setError('Ge├ğerli bir tutar giriniz.');
      setLoading(false);
      return;
    }

    if (!locationId) {
      setError('L├╝tfen bir ┼şube se├ğiniz.');
      setLoading(false);
      return;
    }

    try {
      const res = await createTransaction({
        categoryName,
        type,
        amount,
        paymentMethod,
        description,
        staffId: staffId || undefined,
        locationId: locationId || undefined
      });

      if (res.success) {
        setModalOpen(false);
      } else {
        setError(res.error || '─░┼şlem kaydedilemedi.');
      }
    } catch (err) {
      setError('Ba─şlant─▒ hatas─▒ olu┼ştu.');
    } finally {
      setLoading(false);
    }
  };

  const getMethodIcon = (method: string) => {
    if (method === 'CASH') return <Wallet size={14} className="text-amber-600" />;
    if (method === 'CARD') return <CreditCard size={14} className="text-blue-600" />;
    return <Landmark size={14} className="text-purple-600" />;
  };

  return (
    <div className="space-y-8">
      {/* ┼Şube Filtreleme (Premium Tab Tasar─▒m─▒) */}
      <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex items-center gap-2">
          <MapPin className="text-[var(--color-primary-500)]" size={18} />
          <span className="text-sm font-bold text-gray-700">┼Şube Filtresi:</span>
        </div>
        <div className="flex flex-wrap gap-2">
          <button
            onClick={() => setSelectedLocationId('ALL')}
            className={`px-4 py-2 text-xs font-bold rounded-xl transition-all cursor-pointer ${
              selectedLocationId === 'ALL'
                ? 'bg-gray-950 text-white shadow-sm'
                : 'bg-gray-50 hover:bg-gray-100 text-gray-600'
            }`}
          >
            T├╝m ┼Şubeler
          </button>
          {locations.map((loc) => (
            <button
              key={loc.id}
              onClick={() => setSelectedLocationId(loc.id)}
              className={`px-4 py-2 text-xs font-bold rounded-xl transition-all cursor-pointer ${
