import { prisma } from '@/lib/prisma';
import { cookies } from 'next/headers';
import { redirect } from 'next/navigation';
import AdminShell from '@/components/admin/AdminShell';
import AccountingClient from './AccountingClient';
import { TrendingUp, Landmark } from 'lucide-react';

export default async function AccountingPage() {
  const cookieStore = await cookies();
  const token = cookieStore.get('admin_token');


  // G├╝venlik Kontrol├╝
  if (!token || token.value !== 'authenticated') {
    redirect(`/admin/login`);
  }

  // 1. ─░┼şlemleri ├ğek (Kategori ve Staff ile)
  let transactions: any[] = [];
  let staffList: any[] = [];
  let completedAppointments: any[] = [];
  let locations: any[] = [];

  try {
    transactions = await prisma.transaction.findMany({
      include: {
        category: true,
        staff: true,
        location: true
      },
      orderBy: {
        date: 'desc'
      }
    });

    // 2. Aktif personelleri ├ğek
    staffList = await prisma.staff.findMany({
      where: { isDeleted: false },
      orderBy: { name: 'asc' }
    });

    // 2.1. Aktif ┼şubeleri ├ğek
    locations = await prisma.location.findMany({
      where: { isDeleted: false, isActive: true },
      orderBy: { name: 'asc' }
    });

    // 3. Tamamlanan randevular─▒ ├ğek (Ciro ve komisyon hesaplama i├ğin)
    completedAppointments = await prisma.appointment.findMany({
      where: { status: 'COMPLETED' },
      include: {
        service: true,
        staff: true,
        staffCommission: true
      }
    });
  } catch (error) {
    console.error("Muhasebe verileri ├ğekilemedi:", error);
  }

  // Tipleri g├╝venli hale getirelim (Decimal -> String)
  const formattedTransactions = transactions.map((t) => ({
    id: t.id,
    type: t.type,
    amount: t.amount.toString(),
    paymentMethod: t.paymentMethod,
    date: t.date.toISOString(),
    description: t.description,
    locationId: t.locationId,
    locationName: t.location ? (t.location.branchName || t.location.name) : '┼Şube Belirtilmemi┼ş',
    category: {
      name: t.category.name,
    },
    staff: t.staff ? { name: t.staff.name } : null
  }));

  const formattedStaffList = staffList.map((st) => ({
    id: st.id,
    name: st.name
  }));

  const formattedLocations = locations.map((l) => ({
    id: l.id,
    name: l.branchName || l.name
  }));

  // Personel hakedi┼ş ciro/komisyon hesaplamas─▒
  const staffPayoutsMap: Record<string, { staffId: string; name: string; appointmentCount: number; totalRevenue: number; commissionEarned: number }> = {};

  // Ba┼şlang─▒├ğta t├╝m aktif personelleri ekle (cirosu olmasa da listelensinler)
  staffList.forEach((st) => {
    staffPayoutsMap[st.id] = {
      staffId: st.id,
      name: st.name,
      appointmentCount: 0,
      totalRevenue: 0,
      commissionEarned: 0
    };
  });

  // Tamamlanan randevular─▒ tara ve hesapla
  completedAppointments.forEach((appt) => {
    if (!appt.staffId) return;

    // E─şer haritada personel yoksa ekle (├Ârne─şin pasif yap─▒lm─▒┼ş ama eski ciro kayd─▒ varsa)
    if (!staffPayoutsMap[appt.staffId]) {
      staffPayoutsMap[appt.staffId] = {
        staffId: appt.staffId,
        name: appt.staff?.name || 'Bilinmeyen ├çal─▒┼şan',
        appointmentCount: 0,
        totalRevenue: 0,
        commissionEarned: 0
      };
    }

    const payout = staffPayoutsMap[appt.staffId];
    payout.appointmentCount += 1;

    const price = parseFloat(appt.priceAtBooking.toString());
    payout.totalRevenue += price;

    // Komisyon hesab─▒: E─şer veritaban─▒nda haz─▒r komisyon kayd─▒ varsa onu kullan, yoksa ├ğal─▒┼şan oran─▒na g├Âre hesapla
    let commAmount = 0;
    if (appt.staffCommission) {
      commAmount = parseFloat(appt.staffCommission.amount.toString());
    } else if (appt.staff?.commissionRate) {
      const rate = parseFloat(appt.staff.commissionRate.toString());
      commAmount = (price * rate) / 100;
    }
    payout.commissionEarned += commAmount;
  });

  const staffPayouts = Object.values(staffPayoutsMap).sort((a, b) => b.commissionEarned - a.commissionEarned);

  return (
    <AdminShell title="Muhasebe & Finansal Raporlama">
          <AccountingClient 
            transactions={formattedTransactions} 
            staffList={formattedStaffList} 
            staffPayouts={staffPayouts} 
            locations={formattedLocations}

          />
    </AdminShell>
  );
}

