                >
                  {loading ? 'Kaydediliyor...' : 'Notlar─▒ Kaydet'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from 'react';
import { createCoupon, updateCoupon, deleteCoupon } from '@/app/actions/coupon';
import { DiscountType } from '@prisma/client';
import { 
  Plus, 
  Search, 
  Calendar, 
  Ticket, 
  Percent, 
  DollarSign, 
  CheckCircle, 
  AlertCircle,
  X,
  Edit,
  Trash2,
  Lock,
  Unlock,
  Check
} from 'lucide-react';

interface CouponItem {
  id: string;
  code: string;
  discountType: DiscountType;
  value: number;
  startDate: string;
  endDate: string;
  usageLimit: number | null;
  usageCount: number;
  isActive: boolean;
  createdAt: string;
}

interface CouponsClientProps {
  initialCoupons: CouponItem[];
}

export default function CouponsClient({ initialCoupons }: CouponsClientProps) {
  const [coupons, setCoupons] = useState<CouponItem[]>(initialCoupons);
  const [searchTerm, setSearchTerm] = useState<string>('');

  // Modal durumlar─▒
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [editingCoupon, setEditingCoupon] = useState<CouponItem | null>(null);

  // Form inputlar─▒
  const [code, setCode] = useState<string>('');
  const [discountType, setDiscountType] = useState<DiscountType>('PERCENTAGE');
  const [value, setValue] = useState<string>('');
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');
  const [usageLimit, setUsageLimit] = useState<string>('');
  const [isActive, setIsActive] = useState<boolean>(true);

  const [formLoading, setFormLoading] = useState<boolean>(false);
  const [loadingId, setLoadingId] = useState<string | null>(null);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const showFeedback = (type: 'success' | 'error', text: string) => {
    setMessage({ type, text });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleOpenCreateModal = () => {
    setEditingCoupon(null);
    setCode('');
    setDiscountType('PERCENTAGE');
    setValue('');
    const today = new Date().toISOString().split('T')[0];
    setStartDate(today);
    const nextMonth = new Date();
    nextMonth.setMonth(nextMonth.getMonth() + 1);
    setEndDate(nextMonth.toISOString().split('T')[0]);
    setUsageLimit('');
    setIsActive(true);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (coupon: CouponItem) => {
    setEditingCoupon(coupon);
    setCode(coupon.code);
    setDiscountType(coupon.discountType);
    setValue(coupon.value.toString());
    setStartDate(coupon.startDate);
    setEndDate(coupon.endDate);
    setUsageLimit(coupon.usageLimit?.toString() || '');
    setIsActive(coupon.isActive);
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormLoading(true);

    const formData = new FormData();
    formData.append('code', code);
    formData.append('discountType', discountType);
    formData.append('value', value);
    formData.append('startDate', startDate);
    formData.append('endDate', endDate);
    formData.append('usageLimit', usageLimit);
    formData.append('isActive', isActive.toString());

    let result;
    if (editingCoupon) {
      result = await updateCoupon(editingCoupon.id, formData);
    } else {
      result = await createCoupon(formData);
    }

    setFormLoading(false);

    if (result.success) {
      if (editingCoupon) {
        setCoupons(prev => prev.map(c => c.id === editingCoupon.id ? {
          ...c,
          code: code.toUpperCase().trim(),
          discountType,
          value: parseFloat(value),
          startDate,
          endDate,
          usageLimit: usageLimit ? parseInt(usageLimit) : null,
          isActive
        } : c));
        showFeedback('success', 'Kupon ba┼şar─▒yla g├╝ncellendi.');
      } else if (result.data) {
        const newC = result.data as any;
        setCoupons(prev => [{
          id: newC.id,
          code: newC.code,
          discountType: newC.discountType,
          value: Number(newC.value),
          startDate: new Date(newC.startDate).toISOString().split('T')[0],
          endDate: new Date(newC.endDate).toISOString().split('T')[0],
          usageLimit: newC.usageLimit,
          usageCount: newC.usageCount,
          isActive: newC.isActive,
          createdAt: newC.createdAt
        }, ...prev]);
        showFeedback('success', 'Kupon ba┼şar─▒yla olu┼şturuldu.');
      }
      setIsModalOpen(false);
    } else {
      showFeedback('error', result.error || '─░┼şlem ba┼şar─▒s─▒z oldu.');
    }
  };

  const handleToggleStatus = async (id: string, currentStatus: boolean) => {
    setLoadingId(id);
    const formData = new FormData();
    const c = coupons.find(item => item.id === id)!;
    formData.append('code', c.code);
    formData.append('discountType', c.discountType);
    formData.append('value', c.value.toString());
    formData.append('startDate', c.startDate);
    formData.append('endDate', c.endDate);
    formData.append('usageLimit', c.usageLimit?.toString() || '');
    formData.append('isActive', (!currentStatus).toString());

    const result = await updateCoupon(id, formData);
    setLoadingId(null);

    if (result.success) {
      setCoupons(prev => prev.map(item => item.id === id ? { ...item, isActive: !currentStatus } : item));
      showFeedback('success', `Kupon durumu ${!currentStatus ? 'aktif' : 'pasif'} yap─▒ld─▒.`);
    } else {
      showFeedback('error', result.error || '─░┼şlem ba┼şar─▒s─▒z oldu.');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Bu kuponu pasifle┼ştirmek istedi─şinize emin misiniz?')) return;
    setLoadingId(id);
    const result = await deleteCoupon(id);
    setLoadingId(null);

    if (result.success) {
      setCoupons(prev => prev.map(c => c.id === id ? { ...c, isActive: false } : c));
      showFeedback('success', 'Kupon pasifle┼ştirildi (soft delete).');
    } else {
      showFeedback('error', result.error || 'Pasifle┼ştirme ba┼şar─▒s─▒z oldu.');
    }
  };

  const filteredCoupons = coupons.filter(c => 
    c.code.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Feedback Message */}
      {message && (
        <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 px-4 py-3 rounded-xl shadow-lg border transition-all duration-300 ${
          message.type === 'success' ? 'bg-green-50 text-green-800 border-green-200' : 'bg-red-50 text-red-800 border-red-200'
        }`}>
          {message.type === 'success' ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-medium">{message.text}</span>
        </div>
      )}

      {/* ├£st ─░┼şlem ├çubu─şu */}
      <div className="bg-white border border-gray-200 rounded-2xl p-4 shadow-sm flex flex-col sm:flex-row gap-4 items-center justify-between">
        <div className="w-full sm:w-80 relative">
          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Kupon kodu ile ara..."
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
          />
        </div>
        <button
          onClick={handleOpenCreateModal}
          className="w-full sm:w-auto bg-[var(--color-rose-600)] text-white px-5 py-2 rounded-xl hover:bg-[var(--color-rose-700)] text-sm font-semibold shadow-sm transition-colors flex items-center justify-center gap-2"
        >
          <Plus size={16} />
          Yeni Kupon Olu┼ştur
        </button>
      </div>

      {/* Tablo Listesi */}
      <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-200 text-xs font-bold text-gray-500 uppercase tracking-wider">
                <th className="py-4 px-6">Kupon Kodu</th>
                <th className="py-4 px-6">─░ndirim T├╝r├╝ & De─şer</th>
                <th className="py-4 px-6">Ge├ğerlilik Tarihi</th>
                <th className="py-4 px-6">Limit / Kullan─▒m</th>
                <th className="py-4 px-6">Durum</th>
                <th className="py-4 px-6 text-right">─░┼şlemler</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 text-sm text-gray-700">
              {filteredCoupons.length === 0 ? (
                <tr>
                  <td colSpan={6} className="py-10 text-center text-gray-400 font-medium">
                    Kay─▒tl─▒ kupon bulunamad─▒.
                  </td>
                </tr>
              ) : (
                filteredCoupons.map((coupon) => {
                  const isExpired = new Date(coupon.endDate) < new Date();
                  return (
                    <tr key={coupon.id} className="hover:bg-gray-50 transition-colors">
                      <td className="py-4 px-6">
                        <span className="flex items-center gap-2 font-mono font-bold text-[var(--color-rose-700)] bg-[var(--color-rose-50)] border border-[var(--color-rose-100)] px-2.5 py-1 rounded-lg w-fit text-sm">
                          <Ticket size={14} />
                          {coupon.code}
                        </span>
                      </td>
                      <td className="py-4 px-6">
                        <span className="flex items-center gap-1 font-semibold text-gray-900">
                          {coupon.discountType === 'PERCENTAGE' ? (
                            <>
                              <Percent size={14} className="text-gray-400" />
                              {coupon.value} ─░ndirim
                            </>
                          ) : (
                            <>
                              <DollarSign size={14} className="text-gray-400" />
                              {coupon.value} TL ─░ndirim
                            </>
                          )}
                        </span>
                      </td>
                      <td className="py-4 px-6 text-gray-500 text-xs">
                        <span className="flex items-center gap-1">
                          <Calendar size={14} className="text-gray-400" />
                          {coupon.startDate} / {coupon.endDate}
                        </span>
                        {isExpired && (
                          <span className="text-red-500 font-bold block mt-0.5">S├╝resi Doldu</span>
                        )}
                      </td>
                      <td className="py-4 px-6 text-xs font-medium text-gray-600">
                        {coupon.usageLimit ? (
                          <span>{coupon.usageCount} / {coupon.usageLimit} Kullan─▒m</span>
                        ) : (
                          <span>{coupon.usageCount} Kullan─▒m (Limitsiz)</span>
                        )}
                      </td>
                      <td className="py-4 px-6">
                        <span className={`inline-flex items-center gap-1 text-xs px-2.5 py-1 rounded-full font-semibold border ${
                          coupon.isActive && !isExpired
                            ? 'bg-green-50 text-green-700 border-green-200' 
                            : 'bg-red-50 text-red-700 border-red-200'
                        }`}>
                          {coupon.isActive && !isExpired ? 'Aktif' : 'Pasif'}
                        </span>
                      </td>
                      <td className="py-4 px-6 text-right">
                        <div className="flex justify-end gap-2">
                          <button
                            onClick={() => handleToggleStatus(coupon.id, coupon.isActive)}
                            disabled={loadingId === coupon.id}
                            className={`p-1.5 rounded-lg border transition-colors ${
                              coupon.isActive 
                                ? 'text-gray-400 border-gray-200 hover:text-gray-600 hover:bg-gray-50' 
                                : 'text-green-600 border-green-200 bg-green-50 hover:bg-green-100'
                            }`}
                            title={coupon.isActive ? 'Pasife Al' : 'Aktife Al'}
                          >
                            {coupon.isActive ? <Lock size={15} /> : <Unlock size={15} />}
                          </button>

                          <button
                            onClick={() => handleOpenEditModal(coupon)}
                            disabled={loadingId === coupon.id}
                            className="p-1.5 rounded-lg border text-gray-600 border-gray-200 hover:bg-gray-50 transition-colors"
                            title="D├╝zenle"
                          >
                            <Edit size={15} />
                          </button>

                          <button
                            onClick={() => handleDelete(coupon.id)}
                            disabled={loadingId === coupon.id}
                            className="p-1.5 rounded-lg border text-red-600 border-red-200 hover:bg-red-50 transition-colors"
                            title="Kuponu Pasifle┼ştir (Soft Delete)"
                          >
                            <Trash2 size={15} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal - Ekleme / D├╝zenleme */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm transition-all duration-300">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-200">
            {/* Header */}
            <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <h3 className="text-base font-bold text-gray-900">
                {editingCoupon ? 'Kuponu D├╝zenle' : 'Yeni Kupon Olu┼ştur'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 transition-colors">
                <X size={18} />
              </button>
            </div>

            {/* Form */}
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              {/* Kod */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Kupon Kodu</label>
                <input
                  type="text"
                  required
                  value={code}
                  onChange={(e) => setCode(e.target.value)}
                  placeholder="YENIYIL2026"
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white uppercase font-mono font-bold"
                />
              </div>

              {/* ─░ndirim T├╝r├╝ */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">─░ndirim T├╝r├╝</label>
                <select
                  value={discountType}
                  onChange={(e) => setDiscountType(e.target.value as DiscountType)}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white"
                >
                  <option value="PERCENTAGE">Y├╝zde (%)</option>
                  <option value="FIXED">Sabit Tutar (TL)</option>
                </select>
              </div>

              {/* ─░ndirim De─şeri */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">─░ndirim De─şeri</label>
                <input
                  type="number"
                  required
                  min={1}
                  step="0.01"
                  value={value}
                  onChange={(e) => setValue(e.target.value)}
                  placeholder={discountType === 'PERCENTAGE' ? '20' : '100'}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white"
                />
              </div>

              {/* Ba┼şlang─▒├ğ & Biti┼ş Tarihleri */}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Ba┼şlang─▒├ğ</label>
                  <input
                    type="date"
                    required
                    value={startDate}
                    onChange={(e) => setStartDate(e.target.value)}
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Biti┼ş</label>
                  <input
                    type="date"
                    required
                    value={endDate}
                    onChange={(e) => setEndDate(e.target.value)}
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white"
                  />
                </div>
              </div>

              {/* Kullan─▒m Limiti */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Kullan─▒m Limiti (Opsiyonel)</label>
                <input
                  type="number"
                  min={1}
                  value={usageLimit}
                  onChange={(e) => setUsageLimit(e.target.value)}
                  placeholder="├ûrn: 100 (Bo┼ş b─▒rak─▒l─▒rsa limitsiz)"
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white"
                />
              </div>

              {/* Aktiflik Durumu (Sadece d├╝zenlemede g├Âsterilebilir veya her zaman) */}
              <div className="flex items-center gap-2 pt-2">
                <input
                  type="checkbox"
                  id="isActive"
                  checked={isActive}
                  onChange={(e) => setIsActive(e.target.checked)}
                  className="w-4 h-4 text-[var(--color-rose-600)] border-gray-300 rounded focus:ring-[var(--color-rose-500)]"
                />
                <label htmlFor="isActive" className="text-sm font-semibold text-gray-700 cursor-pointer">Kupon Aktif Olsun</label>
              </div>

              {/* Submit Buttons */}
              <div className="flex gap-3 justify-end pt-4 border-t border-gray-100">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-gray-200 rounded-xl text-sm font-semibold text-gray-600 hover:bg-gray-50 transition-colors"
                >
                  ─░ptal
                </button>
                <button
                  type="submit"
                  disabled={formLoading}
                  className="bg-[var(--color-rose-600)] text-white px-5 py-2 rounded-xl hover:bg-[var(--color-rose-700)] text-sm font-semibold shadow-sm transition-colors disabled:opacity-50 flex items-center gap-1"
                >
                  {formLoading ? 'Kaydediliyor...' : editingCoupon ? 'G├╝ncelle' : 'Olu┼ştur'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from 'react';
import { Mail, Save, Eye, EyeOff, Edit3, Check, AlertCircle, Code, X, MonitorSmartphone } from 'lucide-react';
import { updateEmailTemplate } from '@/app/actions/email-template';

interface Template {
  id: string;
  key: string;
  name: string;
  subject: string;
  body: string;
  isActive: boolean;
  updatedAt: string;
}

interface Props {
  templates: Template[];
}

const variablesList = [
  { key: '{{customerName}}', desc: 'M├╝┼şteri ad─▒' },
  { key: '{{serviceName}}', desc: 'Hizmet ad─▒' },
  { key: '{{date}}', desc: 'Randevu tarihi' },
  { key: '{{time}}', desc: 'Randevu saati' },
  { key: '{{customerEmail}}', desc: 'M├╝┼şteri e-postas─▒' },
];

export default function EmailTemplateClient({ templates }: Props) {
  const [items, setItems] = useState<Template[]>(templates);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editData, setEditData] = useState<{ name: string; subject: string; body: string }>({ name: '', subject: '', body: '' });

  // ├çok dilli y├Ânetim state'leri
  const [isMultiLang, setIsMultiLang] = useState(false);
  const [selectedLang, setSelectedLang] = useState<string>('TR');
  const [editDataMulti, setEditDataMulti] = useState<{
    [lang: string]: { subject: string; body: string }
  }>({
    TR: { subject: '', body: '' },
    EN: { subject: '', body: '' },
    RU: { subject: '', body: '' },
    DE: { subject: '', body: '' }
  });

  const [editTab, setEditTab] = useState<'html' | 'preview'>('html');
  const [previewId, setPreviewId] = useState<string | null>(null);
  const [previewLang, setPreviewLang] = useState<string>('TR');
  const [loading, setLoading] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const showFeedback = (type: 'success' | 'error', text: string) => {
    setFeedback({ type, text });
    setTimeout(() => setFeedback(null), 3000);
  };

  const startEdit = (t: Template) => {
    setEditingId(t.id);
    setEditTab('html');
    setPreviewId(null);

    let parsedSubject: any = null;
    let parsedBody: any = null;
    let isJson = false;

    try {
      parsedSubject = JSON.parse(t.subject);
      parsedBody = JSON.parse(t.body);
      if (parsedSubject && typeof parsedSubject === 'object' && parsedBody && typeof parsedBody === 'object') {
        isJson = true;
      }
    } catch (e) {
      // JSON de─şil
    }

    if (isJson) {
      setIsMultiLang(true);
      setEditDataMulti({
        TR: { subject: parsedSubject.TR || '', body: parsedBody.TR || '' },
        EN: { subject: parsedSubject.EN || '', body: parsedBody.EN || '' },
        RU: { subject: parsedSubject.RU || '', body: parsedBody.RU || '' },
        DE: { subject: parsedSubject.DE || '', body: parsedBody.DE || '' }
      });
      setSelectedLang('TR');
      setEditData({ name: t.name, subject: '', body: '' });
    } else {
      setIsMultiLang(false);
      setEditData({ name: t.name, subject: t.subject, body: t.body });
    }
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditData({ name: '', subject: '', body: '' });
  };

  const saveEdit = async () => {
    if (!editingId) return;
    setLoading(true);

    let dataToSave: { name: string; subject: string; body: string } = {
      name: editData.name,
      subject: editData.subject,
      body: editData.body
    };

    if (isMultiLang) {
      const subjects: Record<string, string> = {};
      const bodies: Record<string, string> = {};
      Object.keys(editDataMulti).forEach(lang => {
        subjects[lang] = editDataMulti[lang].subject;
        bodies[lang] = editDataMulti[lang].body;
      });

      dataToSave = {
        name: editData.name,
        subject: JSON.stringify(subjects),
        body: JSON.stringify(bodies)
      };
    }

    const result = await updateEmailTemplate(editingId, dataToSave);
    setLoading(false);

    if (result.success) {
      setItems(prev => prev.map(t => t.id === editingId ? { ...t, ...dataToSave } : t));
      showFeedback('success', '┼Şablon kaydedildi.');
      setEditingId(null);
    } else {
      showFeedback('error', result.error || 'Hata olu┼ştu.');
    }
  };

  const toggleActive = async (id: string, isActive: boolean) => {
    const result = await updateEmailTemplate(id, { isActive: !isActive });
    if (result.success) {
      setItems(prev => prev.map(t => t.id === id ? { ...t, isActive: !isActive } : t));
      showFeedback('success', isActive ? '┼Şablon pasif yap─▒ld─▒.' : '┼Şablon aktif yap─▒ld─▒.');
    }
  };

  // ├ûnizleme: de─şi┼şkenleri ├Ârnek verilerle de─şi┼ştir
  const renderPreview = (body: string) => {
    if (!body) return '';
    return body
      .replace(/\{\{customerName\}\}/g, 'Ay┼şe Y─▒lmaz')
      .replace(/\{\{serviceName\}\}/g, '─░pek Kirpik Klasik')
      .replace(/\{\{date\}\}/g, '8 Haziran 2026 Pazartesi')
      .replace(/\{\{time\}\}/g, '14:30')
      .replace(/\{\{customerEmail\}\}/g, 'ayse@email.com');
  };

  return (
    <div className="space-y-6">
      {/* Feedback */}
      {feedback && (
        <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 px-4 py-3 rounded-xl shadow-lg border ${
          feedback.type === 'success' ? 'bg-green-50 text-green-800 border-green-200' : 'bg-red-50 text-red-800 border-red-200'
        }`}>
          {feedback.type === 'success' ? <Check size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-medium">{feedback.text}</span>
        </div>
      )}

      {/* De─şi┼şkenler Referans */}
      <div className="bg-blue-50/50 rounded-2xl border border-blue-100 p-4">
        <h3 className="text-xs font-bold text-blue-800 uppercase tracking-wider mb-2 flex items-center gap-1">
          <Code size={14} /> Kullan─▒labilir De─şi┼şkenler
        </h3>
        <div className="flex flex-wrap gap-2">
          {variablesList.map(v => (
            <span key={v.key} className="inline-flex items-center gap-1 px-2 py-1 bg-white rounded-lg border border-blue-100 text-xs">
              <code className="font-mono text-blue-700 font-bold">{v.key}</code>
              <span className="text-gray-500">ÔÇö {v.desc}</span>
            </span>
          ))}
        </div>
      </div>

      {/* ┼Şablon Listesi */}
      {items.map(template => {
        let isTmplMulti = false;
        try {
          const s = JSON.parse(template.subject);
          const b = JSON.parse(template.body);
          if (s && typeof s === 'object' && b && typeof b === 'object') {
            isTmplMulti = true;
          }
        } catch(e) {}

        return (
          <div key={template.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
            {/* Header */}
            <div className="p-5 flex items-center justify-between border-b border-gray-100">
              <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${template.isActive ? 'bg-[var(--color-rose-50)] text-[var(--color-rose-600)]' : 'bg-gray-100 text-gray-400'}`}>
                  <Mail size={16} />
                </div>
                <div>
                  <h3 className="font-bold text-gray-800 text-sm">
                    {template.name}
                    {isTmplMulti && (
                      <span className="ml-2 inline-flex items-center px-1.5 py-0.5 rounded-md text-[10px] font-medium bg-rose-50 text-rose-700 border border-rose-100">
                        ├çok Dilli (TR, EN, RU, DE)
                      </span>
                    )}
                  </h3>
                  <p className="text-[10px] text-gray-400 font-mono mt-0.5">{template.key}</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={() => toggleActive(template.id, template.isActive)}
                  className={`px-2.5 py-1 rounded-lg text-[10px] font-bold border ${
                    template.isActive
                      ? 'bg-green-50 text-green-700 border-green-200'
                      : 'bg-gray-50 text-gray-500 border-gray-200'
                  }`}
                >
                  {template.isActive ? 'Aktif' : 'Pasif'}
                </button>
                <button
                  onClick={() => {
                    if (previewId === template.id) {
                      setPreviewId(null);
                    } else {
                      setPreviewId(template.id);
                      setPreviewLang('TR');
                    }
                  }}
                  className="p-2 rounded-lg bg-gray-50 text-gray-600 hover:bg-gray-100 transition-colors"
                  title="├ûnizleme"
                >
                  {previewId === template.id ? <EyeOff size={14} /> : <Eye size={14} />}
                </button>
                <button
                  onClick={() => startEdit(template)}
                  className="p-2 rounded-lg bg-[var(--color-rose-50)] text-[var(--color-rose-600)] hover:bg-[var(--color-rose-100)] transition-colors"
                  title="D├╝zenle"
                >
                  <Edit3 size={14} />
                </button>
              </div>
            </div>

            {/* D├╝zenleme */}
            {editingId === template.id && (
              <div className="p-5 space-y-4 bg-gray-50/50 border-b border-gray-100">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">┼Şablon Ad─▒ (Admin)</label>
                    <input
                      value={editData.name}
                      onChange={e => setEditData({ ...editData, name: e.target.value })}
                      className="w-full px-3 py-2 bg-white border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
                    />
                  </div>
                  {!isMultiLang && (
                    <div>
                      <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">E-posta Konusu</label>
                      <input
                        value={editData.subject}
                        onChange={e => setEditData({ ...editData, subject: e.target.value })}
                        className="w-full px-3 py-2 bg-white border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
                      />
                    </div>
                  )}
                </div>

                {/* ├çok Dilli ise Dil Sekmeleri */}
                {isMultiLang && (
                  <div className="flex border-b border-gray-200 gap-1 bg-white p-1 rounded-xl border">
                    {(['TR', 'EN', 'RU', 'DE'] as const).map(lang => (
                      <button
                        key={lang}
                        type="button"
                        onClick={() => setSelectedLang(lang)}
                        className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                          selectedLang === lang 
                            ? 'bg-[var(--color-rose-600)] text-white shadow-sm' 
                            : 'text-gray-500 hover:bg-gray-50 hover:text-gray-700'
                        }`}
                      >
                        {lang === 'TR' ? '­şç╣­şçÀ T├╝rk├ğe' : lang === 'EN' ? '­şç║­şç© English' : lang === 'RU' ? '­şçÀ­şç║ ºáªâªüªüº║º©º╣' : '­şç®­şç¬ Deutsch'}
                      </button>
                    ))}
                  </div>
                )}

                {/* Dil Sekmesi ─░├ğindeki Konu Sat─▒r─▒ */}
                {isMultiLang && (
                  <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">
                      E-posta Konusu ({selectedLang})
                    </label>
                    <input
                      value={editDataMulti[selectedLang].subject}
                      onChange={e => setEditDataMulti({
                        ...editDataMulti,
                        [selectedLang]: { ...editDataMulti[selectedLang], subject: e.target.value }
                      })}
                      className="w-full px-3 py-2 bg-white border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
                      placeholder={`${selectedLang} dilindeki konu sat─▒r─▒`}
                    />
                  </div>
                )}

                {/* HTML / G├Ârsel Sekmeleri */}
                <div>
                  <div className="flex items-center gap-1 mb-2">
                    <button
                      onClick={() => setEditTab('html')}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                        editTab === 'html'
                          ? 'bg-gray-800 text-white shadow-sm'
                          : 'bg-white text-gray-500 border border-gray-200 hover:bg-gray-50'
                      }`}
                    >
                      <Code size={12} /> HTML Kodu
                    </button>
                    <button
                      onClick={() => setEditTab('preview')}
                      className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold transition-all ${
                        editTab === 'preview'
                          ? 'bg-[var(--color-rose-600)] text-white shadow-sm'
                          : 'bg-white text-gray-500 border border-gray-200 hover:bg-gray-50'
                      }`}
                    >
                      <MonitorSmartphone size={12} /> G├Ârsel ├ûnizleme
                    </button>
                  </div>

                  {editTab === 'html' ? (
                    <textarea
                      value={isMultiLang ? editDataMulti[selectedLang].body : editData.body}
                      onChange={e => {
                        if (isMultiLang) {
                          setEditDataMulti({
                            ...editDataMulti,
                            [selectedLang]: { ...editDataMulti[selectedLang], body: e.target.value }
                          });
                        } else {
                          setEditData({ ...editData, body: e.target.value });
                        }
                      }}
                      rows={16}
                      className="w-full px-3 py-2 bg-gray-900 text-green-400 border border-gray-700 rounded-xl text-xs font-mono focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] resize-y leading-relaxed"
                      spellCheck={false}
                    />
                  ) : (
                    <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
                      {/* Konu sat─▒r─▒ */}
                      <div className="px-4 py-3 bg-gray-50 border-b border-gray-100">
                        <p className="text-xs text-gray-500">
                          <span className="font-bold text-gray-700">Konu: </span>
                          {renderPreview(isMultiLang ? editDataMulti[selectedLang].subject : editData.subject)}
                        </p>
                        <p className="text-[10px] text-gray-400 mt-1">
                          <span className="font-bold">Kimden: </span>
                          Nails & Lashes Studio &lt;info@nailslashes.com&gt;
                        </p>
                      </div>
                      {/* Mail i├ğeri─şi */}
                      <div className="p-6 flex justify-center bg-gray-100/50">
                        <div
                          className="w-full max-w-[600px] overflow-x-auto"
                          dangerouslySetInnerHTML={{ __html: renderPreview(isMultiLang ? editDataMulti[selectedLang].body : editData.body) }}
                        />
                      </div>
                    </div>
                  )}
                </div>

                <div className="flex justify-end gap-2">
                  <button
                    onClick={cancelEdit}
                    className="px-4 py-2 border border-gray-200 text-gray-600 rounded-xl text-xs font-semibold hover:bg-gray-50"
                  >
                    ─░ptal
                  </button>
                  <button
                    onClick={saveEdit}
                    disabled={loading}
                    className="flex items-center gap-1 bg-[var(--color-rose-600)] text-white px-5 py-2 rounded-xl hover:bg-[var(--color-rose-700)] text-xs font-semibold shadow-sm disabled:opacity-50"
                  >
                    <Save size={14} /> {loading ? 'Kaydediliyor...' : 'Kaydet'}
                  </button>
                </div>
              </div>
            )}

            {/* H─▒zl─▒ ├ûnizleme (d├╝zenleme d─▒┼ş─▒nda) */}
            {previewId === template.id && editingId !== template.id && (
              <div className="bg-white border-t border-gray-100">
                <div className="px-5 py-3 bg-gray-50 border-b border-gray-100 flex items-center justify-between">
                  <p className="text-[10px] font-bold text-gray-400 uppercase">E-posta ├ûnizlemesi (├ûrnek Verilerle)</p>
                  <button onClick={() => setPreviewId(null)} className="text-gray-400 hover:text-gray-600"><X size={14} /></button>
                </div>

                {/* ├ûnizlemede Dil Sekmeleri */}
                {isTmplMulti && (
                  <div className="px-5 py-2 bg-white border-b border-gray-100 flex gap-2">
                    {(['TR', 'EN', 'RU', 'DE'] as const).map(lang => (
                      <button
                        key={lang}
                        onClick={() => setPreviewLang(lang)}
                        className={`px-3 py-1 rounded-lg text-xs font-bold transition-all border ${
                          previewLang === lang
                            ? 'bg-rose-50 text-rose-700 border-rose-200'
                            : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'
                        }`}
                      >
                        {lang === 'TR' ? 'TR' : lang === 'EN' ? 'EN' : lang === 'RU' ? 'RU' : 'DE'}
                      </button>
                    ))}
                  </div>
                )}

                <div className="px-4 py-3 bg-gray-50/50 border-b border-gray-100">
                  <p className="text-xs text-gray-500">
                    <span className="font-bold text-gray-700">Konu: </span>
                    {(() => {
                      if (isTmplMulti) {
                        try {
                          const s = JSON.parse(template.subject);
                          return renderPreview(s[previewLang] || s['TR'] || template.subject);
                        } catch(e) {}
                      }
                      return renderPreview(template.subject);
                    })()}
                  </p>
                </div>
                <div className="p-6 flex justify-center bg-gray-100/30">
                  <div
                    className="w-full max-w-[600px] overflow-x-auto"
                    dangerouslySetInnerHTML={{ 
                      __html: (() => {
                        if (isTmplMulti) {
                          try {
                            const b = JSON.parse(template.body);
                            return renderPreview(b[previewLang] || b['TR'] || template.body);
                          } catch(e) {}
                        }
                        return renderPreview(template.body);
                      })()
                    }}
                  />
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { useState } from 'react';
import { createFaq, updateFaq, deleteFaq } from '@/app/actions/faq';
import { Language } from '@prisma/client';
import { 
  Plus, 
  Search, 
  Globe, 
  Settings, 
  CheckCircle, 
  AlertCircle,
  X,
  Edit,
  Trash2,
  Check,
  Eye,
  Info,
  HelpCircle,
  Link2
} from 'lucide-react';

interface FaqItem {
  id: string;
  question: string;
  answer: string;
  language: Language;
  isActive: boolean;
  order: number;
  schemaActive: boolean;
  pageId: string | null;
  serviceId: string | null;
  blogPostId: string | null;
  serviceName: string | null;
  pageTitle: string | null;
}

interface DropdownItem {
  id: string;
  name?: string;
  title?: string;
}

interface FaqClientProps {
  initialFaqs: FaqItem[];
  services: DropdownItem[];
  pages: DropdownItem[];
}

export default function FaqClient({ initialFaqs, services, pages }: FaqClientProps) {
  const [faqs, setFaqs] = useState<FaqItem[]>(initialFaqs);
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [langFilter, setLangFilter] = useState<string>('ALL');

  // Modal durumlar─▒
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [editingFaq, setEditingFaq] = useState<FaqItem | null>(null);

  // Form inputlar─▒
  const [question, setQuestion] = useState<string>('');
  const [answer, setAnswer] = useState<string>('');
  const [language, setLanguage] = useState<Language>('TR');
  const [isActive, setIsActive] = useState<boolean>(true);
  const [schemaActive, setSchemaActive] = useState<boolean>(true);
  const [order, setOrder] = useState<string>('0');

  const [serviceId, setServiceId] = useState<string>('');
  const [pageId, setPageId] = useState<string>('');

  const [formLoading, setFormLoading] = useState<boolean>(false);
  const [loadingId, setLoadingId] = useState<string | null>(null);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const showFeedback = (type: 'success' | 'error', text: string) => {
    setMessage({ type, text });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleOpenCreateModal = () => {
    setEditingFaq(null);
    setQuestion('');
    setAnswer('');
    setLanguage('TR');
    setIsActive(true);
    setSchemaActive(true);
    setOrder('0');
    setServiceId('');
    setPageId('');
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (faq: FaqItem) => {
    setEditingFaq(faq);
    setQuestion(faq.question);
    setAnswer(faq.answer);
    setLanguage(faq.language);
    setIsActive(faq.isActive);
    setSchemaActive(faq.schemaActive);
    setOrder(faq.order.toString());
    setServiceId(faq.serviceId || '');
    setPageId(faq.pageId || '');
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormLoading(true);

    const formData = new FormData();
    formData.append('question', question);
    formData.append('answer', answer);
    formData.append('language', language);
    formData.append('isActive', isActive.toString());
    formData.append('schemaActive', schemaActive.toString());
    formData.append('order', order);
    formData.append('serviceId', serviceId);
    formData.append('pageId', pageId);

    let result;
    if (editingFaq) {
      result = await updateFaq(editingFaq.id, formData);
    } else {
      result = await createFaq(formData);
    }

    setFormLoading(false);

    if (result.success) {
      window.location.reload();
    } else {
      showFeedback('error', result.error || '─░┼şlem ba┼şar─▒s─▒z oldu.');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Bu soruyu pasifle┼ştirmek (soft delete) istedi─şinize emin misiniz?')) return;
    setLoadingId(id);
    const result = await deleteFaq(id);
    setLoadingId(null);

    if (result.success) {
      setFaqs(prev => prev.map(f => f.id === id ? { ...f, isActive: false } : f));
      showFeedback('success', 'Soru pasifle┼ştirildi.');
    } else {
      showFeedback('error', result.error || '─░┼şlem ba┼şar─▒s─▒z oldu.');
    }
  };

  const filteredFaqs = faqs.filter(faq => {
    const matchesSearch = faq.question.toLowerCase().includes(searchTerm.toLowerCase()) || 
      faq.answer.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesLang = langFilter === 'ALL' || faq.language === langFilter;
    return matchesSearch && matchesLang;
  });

  return (
    <div className="space-y-6">
      {/* Feedback Message */}
      {message && (
        <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 px-4 py-3 rounded-xl shadow-lg border transition-all duration-300 ${
          message.type === 'success' ? 'bg-green-50 text-green-800 border-green-200' : 'bg-red-50 text-red-800 border-red-200'
        }`}>
          {message.type === 'success' ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-medium">{message.text}</span>
        </div>
      )}

      {/* ├£st ─░┼şlem ├çubu─şu */}
      <div className="bg-white border border-gray-200 rounded-2xl p-4 shadow-sm flex flex-col sm:flex-row gap-4 items-center justify-between">
        <div className="w-full sm:w-80 relative">
          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Soru veya cevap ile ara..."
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
          />
        </div>

        <div className="flex flex-wrap gap-3 w-full sm:w-auto">
          <select
            value={langFilter}
            onChange={(e) => setLangFilter(e.target.value)}
            className="px-3 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] bg-white"
          >
            <option value="ALL">T├╝m Diller</option>
            <option value="TR">T├╝rk├ğe (TR)</option>
            <option value="EN">─░ngilizce (EN)</option>
            <option value="RU">Rus├ğa (RU)</option>
            <option value="DE">Almanca (DE)</option>
          </select>

          <button
            onClick={handleOpenCreateModal}
            className="bg-[var(--color-rose-600)] text-white px-5 py-2 rounded-xl hover:bg-[var(--color-rose-700)] text-sm font-semibold shadow-sm transition-colors flex items-center justify-center gap-2"
          >
            <Plus size={16} />
            Yeni Soru Ekle
          </button>
        </div>
      </div>

      {/* FAQ Listesi Tablosu */}
      <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-200 text-xs font-bold text-gray-500 uppercase tracking-wider">
                <th className="py-4 px-6 w-[35%]">Soru</th>
                <th className="py-4 px-6 w-[20%]">E┼şle┼şti─şi Hizmet/Sayfa</th>
                <th className="py-4 px-6">Dil & S─▒ra</th>
                <th className="py-4 px-6">Schema</th>
                <th className="py-4 px-6">Durum</th>
                <th className="py-4 px-6 text-right">─░┼şlemler</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 text-sm text-gray-700">
              {filteredFaqs.length === 0 ? (
                <tr>
                  <td colSpan={6} className="py-10 text-center text-gray-400 font-medium">
                    Kay─▒tl─▒ s─▒k├ğa sorulan soru bulunamad─▒.
                  </td>
                </tr>
              ) : (
                filteredFaqs.map((faq) => (
                  <tr key={faq.id} className="hover:bg-gray-50 transition-colors">
                    <td className="py-4 px-6 font-semibold text-gray-900 leading-normal">
                      <div className="flex gap-2 items-start">
                        <HelpCircle size={16} className="text-gray-400 shrink-0 mt-0.5" />
                        <span>{faq.question}</span>
                      </div>
                    </td>
                    <td className="py-4 px-6">
                      {faq.serviceName ? (
                        <span className="flex items-center gap-1 text-xs text-blue-700 bg-blue-50 px-2 py-1 rounded-lg w-fit border border-blue-100 font-medium">
                          <Link2 size={12} />
                          Hizmet: {faq.serviceName}
                        </span>
                      ) : faq.pageTitle ? (
                        <span className="flex items-center gap-1 text-xs text-indigo-700 bg-indigo-50 px-2 py-1 rounded-lg w-fit border border-indigo-100 font-medium">
                          <Link2 size={12} />
                          Sayfa: {faq.pageTitle}
                        </span>
                      ) : (
                        <span className="text-xs text-gray-400 italic">Genel Soru</span>
                      )}
                    </td>
                    <td className="py-4 px-6 text-xs font-semibold">
                      <div className="flex flex-col gap-1">
                        <span className="flex items-center gap-1 bg-gray-100 px-2 py-0.5 rounded border border-gray-200 w-fit text-[10px] text-gray-600">
                          <Globe size={11} className="text-gray-400" />
                          {faq.language}
                        </span>
                        <span className="text-[10px] text-gray-400">S─▒ra: {faq.order}</span>
                      </div>
                    </td>
                    <td className="py-4 px-6">
                      <span className={`text-[10px] px-2 py-0.5 rounded font-bold border ${
                        faq.schemaActive
                          ? 'bg-blue-50 text-blue-700 border-blue-100'
                          : 'bg-gray-50 text-gray-400 border-gray-100'
                      }`}>
                        {faq.schemaActive ? 'Google FAQ' : 'Kapal─▒'}
                      </span>
                    </td>
                    <td className="py-4 px-6">
                      <span className={`inline-flex items-center gap-1 text-xs px-2.5 py-1 rounded-full font-semibold border ${
                        faq.isActive 
                          ? 'bg-green-50 text-green-700 border-green-200' 
                          : 'bg-red-50 text-red-700 border-red-200'
                      }`}>
                        {faq.isActive ? 'Aktif' : 'Pasif'}
                      </span>
                    </td>
                    <td className="py-4 px-6 text-right">
                      <div className="flex justify-end gap-2">
                        <button
                          onClick={() => handleOpenEditModal(faq)}
                          disabled={loadingId === faq.id}
                          className="p-1.5 rounded-lg border text-gray-600 border-gray-200 hover:bg-gray-50 transition-colors"
                          title="D├╝zenle"
                        >
                          <Edit size={14} />
                        </button>

                        <button
                          onClick={() => handleDelete(faq.id)}
                          disabled={loadingId === faq.id}
                          className="p-1.5 rounded-lg border text-red-600 border-red-200 hover:bg-red-50 transition-colors"
                          title="Pasifle┼ştir (Soft Delete)"
                        >
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm transition-all duration-300">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-200 max-h-[90vh] flex flex-col">
            {/* Header */}
            <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 shrink-0">
              <h3 className="text-base font-bold text-gray-900">
                {editingFaq ? 'Soruyu D├╝zenle' : 'Yeni Soru Ekle'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 transition-colors">
                <X size={18} />
              </button>
            </div>

            {/* Form */}
            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 space-y-4">
              {/* Dil Se├ğimi */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Soru Dili</label>
                <div className="flex gap-2">
                  {['TR', 'EN', 'RU', 'DE'].map((lang) => (
                    <button
                      key={lang}
                      type="button"
                      onClick={() => setLanguage(lang as Language)}
                      className={`px-3 py-1.5 text-xs font-bold rounded-lg border transition-all ${
                        language === lang
                          ? 'bg-[var(--color-rose-600)] text-white border-[var(--color-rose-600)]'
                          : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                      }`}
                    >
                      {lang}
                    </button>
                  ))}
                </div>
              </div>

              {/* Soru */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Soru</label>
                <input
                  type="text"
                  required
                  value={question}
                  onChange={(e) => setQuestion(e.target.value)}
                  placeholder="├ûrn: Protez t─▒rnak i┼şlemi ne kadar s├╝rer?"
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white font-medium"
                />
              </div>

              {/* Cevap */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Cevap</label>
                <textarea
                  required
                  value={answer}
                  onChange={(e) => setAnswer(e.target.value)}
                  placeholder="Sorunun detayl─▒ cevab─▒n─▒ buraya yaz─▒n..."
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white h-24 resize-none"
                />
              </div>

              {/* E┼şle┼ştirme (Hizmet & Sayfa) */}
              <div className="border border-gray-200 rounded-xl p-4 bg-gray-50 space-y-3">
                <span className="text-[10px] font-bold text-gray-500 uppercase tracking-wider block">Soru Konumland─▒rmas─▒ (E┼şle┼ştirme)</span>

                <div className="grid grid-cols-2 gap-4">
                  {/* Hizmet */}
                  <div>
                    <label className="text-[10px] font-bold text-gray-400 block mb-1">Hizmet Detay Sayfas─▒</label>
                    <select
                      value={serviceId}
                      onChange={(e) => {
                        setServiceId(e.target.value);
                        if (e.target.value) setPageId(''); // ├çak─▒┼şmay─▒ ├Ânlemek i├ğin di─şerini temizle
                      }}
                      className="w-full px-2 py-1.5 bg-white border border-gray-200 rounded-lg text-xs focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
                    >
                      <option value="">-- Hizmet Se├ğ --</option>
                      {services.map(s => (
                        <option key={s.id} value={s.id}>{s.name || s.title}</option>
                      ))}
                    </select>
                  </div>

                  {/* Sayfa */}
                  <div>
                    <label className="text-[10px] font-bold text-gray-400 block mb-1">CMS Sayfas─▒</label>
                    <select
                      value={pageId}
                      onChange={(e) => {
                        setPageId(e.target.value);
                        if (e.target.value) setServiceId(''); // ├çak─▒┼şmay─▒ ├Ânlemek i├ğin di─şerini temizle
                      }}
                      className="w-full px-2 py-1.5 bg-white border border-gray-200 rounded-lg text-xs focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
                    >
                      <option value="">-- Sayfa Se├ğ --</option>
                      {pages.map(p => (
                        <option key={p.id} value={p.id}>{p.title || p.name}</option>
                      ))}
                    </select>
                  </div>
                </div>
              </div>

              {/* S─▒ralama */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Soru G├Âsterim S─▒ras─▒</label>
                <input
                  type="number"
                  value={order}
                  onChange={(e) => setOrder(e.target.value)}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white"
                />
              </div>

              {/* Checkbox Se├ğenekleri */}
              <div className="flex gap-6 pt-2">
                <div className="flex items-center gap-2">
                  <input
                    type="checkbox"
                    id="isActive"
                    checked={isActive}
                    onChange={(e) => setIsActive(e.target.checked)}
                    className="w-4 h-4 text-[var(--color-rose-600)] border-gray-300 rounded focus:ring-[var(--color-rose-500)]"
                  />
                  <label htmlFor="isActive" className="text-sm font-semibold text-gray-700 cursor-pointer">Soru Aktif</label>
                </div>

                <div className="flex items-center gap-2">
                  <input
                    type="checkbox"
                    id="schemaActive"
                    checked={schemaActive}
                    onChange={(e) => setSchemaActive(e.target.checked)}
                    className="w-4 h-4 text-[var(--color-rose-600)] border-gray-300 rounded focus:ring-[var(--color-rose-500)]"
                  />
                  <label htmlFor="schemaActive" className="text-sm font-semibold text-gray-700 cursor-pointer">Google FAQ ┼Şemas─▒ ├£ret</label>
                </div>
              </div>

              {/* Submit Buttons */}
              <div className="flex gap-3 justify-end pt-4 border-t border-gray-100 shrink-0">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="px-4 py-2 border border-gray-200 rounded-xl text-sm font-semibold text-gray-600 hover:bg-gray-50 transition-colors"
                >
                  ─░ptal
                </button>
                <button
                  type="submit"
                  disabled={formLoading}
                  className="bg-[var(--color-rose-600)] text-white px-5 py-2 rounded-xl hover:bg-[var(--color-rose-700)] text-sm font-semibold shadow-sm transition-colors disabled:opacity-50"
                >
                  {formLoading ? 'Kaydediliyor...' : editingFaq ? 'G├╝ncelle' : 'Olu┼ştur'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import Image from 'next/image';
import { useState } from 'react';
import {
  Image as ImageIcon, FolderOpen, Settings,
  Plus, Trash2, Save, Edit, Eye, EyeOff, Star, StarOff,
  ChevronUp, ChevronDown, Search, Loader2, X
} from 'lucide-react';
import {
  createGalleryCategory, updateGalleryCategory, deleteGalleryCategory,
  createGalleryItem, updateGalleryItem, deleteGalleryItem,
  reorderGalleryCategories, reorderGalleryItems, toggleGalleryItemFeatured
} from '@/app/actions/gallery';
import MediaPickerModal from '@/components/admin/MediaPickerModal';

const LANGUAGES = ['TR', 'EN', 'DE', 'RU'] as const;
type Lang = typeof LANGUAGES[number];

interface GalleryAdminClientProps {
  initialCategories: any[];
  initialItems: any[];
  locations: Array<{ id: string; name: string }>;
  services: Array<{ id: string; name: string }>;
}

// ÔòÉÔòÉÔòÉ HELPER ÔòÉÔòÉÔòÉ
function getTrans(translations: any[], lang: string, field: string) {
  const t = translations?.find((tr: any) => tr.language === lang);
  return t?.[field] || '';
}

function slugify(text: string): string {
  return text.toLowerCase()
    .replace(/─ş/g, 'g').replace(/├╝/g, 'u').replace(/┼ş/g, 's')
    .replace(/─▒/g, 'i').replace(/├Â/g, 'o').replace(/├ğ/g, 'c')
    .replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

export default function GalleryAdminClient({ initialCategories, initialItems, locations, services }: GalleryAdminClientProps) {
  const [activeTab, setActiveTab] = useState<'items' | 'categories'>('items');
  const [categories, setCategories] = useState(initialCategories);
  const [items, setItems] = useState(initialItems);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  // ÔòÉÔòÉÔòÉ MODAL STATES ÔòÉÔòÉÔòÉ
  const [showCatModal, setShowCatModal] = useState(false);
  const [editingCat, setEditingCat] = useState<any>(null);
  const [showItemModal, setShowItemModal] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [mediaPickerTarget, setMediaPickerTarget] = useState<'item' | 'catImage' | 'catOg'>('item');

  // ÔòÉÔòÉÔòÉ FORM STATES ÔòÉÔòÉÔòÉ
  const [catForm, setCatForm] = useState({
    isActive: true, order: 0, image: '', ogImage: '', canonical: '', noIndex: false,
    translations: LANGUAGES.map(l => ({ language: l, name: '', slug: '', description: '', seoTitle: '', seoDescription: '' }))
  });
  const [activeCatLang, setActiveCatLang] = useState<Lang>('TR');

  const [itemForm, setItemForm] = useState({
    imageUrl: '', order: 0, isActive: true, isFeatured: false,
    categoryId: '', locationId: '', serviceId: '',
    translations: LANGUAGES.map(l => ({ language: l, title: '', description: '', altText: '' }))
  });
  const [activeItemLang, setActiveItemLang] = useState<Lang>('TR');

  const flash = (msg: string) => { setMessage(msg); setTimeout(() => setMessage(''), 3000); };

  // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
  // KATEGOR─░ FONKS─░YONLARI
  // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
  const openNewCat = () => {
    setEditingCat(null);
    setCatForm({
      isActive: true, order: categories.length, image: '', ogImage: '', canonical: '', noIndex: false,
      translations: LANGUAGES.map(l => ({ language: l, name: '', slug: '', description: '', seoTitle: '', seoDescription: '' }))
    });
    setActiveCatLang('TR');
    setShowCatModal(true);
  };

  const openEditCat = (cat: any) => {
    setEditingCat(cat);
    setCatForm({
      isActive: cat.isActive, order: cat.order, image: cat.image || '', ogImage: cat.ogImage || '',
      canonical: cat.canonical || '', noIndex: cat.noIndex || false,
      translations: LANGUAGES.map(l => {
        const t = cat.translations?.find((tr: any) => tr.language === l);
        return {
          language: l, name: t?.name || '', slug: t?.slug || '', description: t?.description || '',
          seoTitle: t?.seoTitle || '', seoDescription: t?.seoDescription || ''
        };
      })
    });
    setActiveCatLang('TR');
    setShowCatModal(true);
  };

  const saveCat = async () => {
    setSaving(true);
    const payload = { ...catForm, translations: catForm.translations.filter(t => t.name.trim()) };
    if (payload.translations.length === 0) { flash('En az bir dilde kategori ad─▒ giriniz.'); setSaving(false); return; }

    let result;
    if (editingCat) {
      result = await updateGalleryCategory(editingCat.id, payload);
    } else {
      result = await createGalleryCategory(payload);
    }
    if (result.success) {
      flash(editingCat ? 'Kategori g├╝ncellendi!' : 'Kategori olu┼şturuldu!');
      setShowCatModal(false);
      // Refresh
      const fresh = await (await import('@/app/actions/gallery')).getGalleryCategories();
      if (fresh.success) setCategories(fresh.categories);
    } else {
      flash('Hata: ' + (result.error || '─░┼şlem ba┼şar─▒s─▒z.'));
    }
    setSaving(false);
  };

  const removeCat = async (id: string) => {
    if (!confirm('Bu kategoriyi silmek istedi─şinize emin misiniz?')) return;
    const result = await deleteGalleryCategory(id);
    if (result.success) {
      setCategories(prev => prev.filter(c => c.id !== id));
      flash('Kategori silindi.');
    }
  };

  const moveCat = async (index: number, dir: -1 | 1) => {
    const arr = [...categories];
    const target = index + dir;
    if (target < 0 || target >= arr.length) return;
    [arr[index], arr[target]] = [arr[target], arr[index]];
    arr.forEach((c, i) => c.order = i);
    setCategories(arr);
    await reorderGalleryCategories(arr.map(c => ({ id: c.id, order: c.order })));
  };

  const updateCatTrans = (field: string, value: string) => {
    setCatForm(prev => ({
      ...prev,
      translations: prev.translations.map(t =>
        t.language === activeCatLang ? { ...t, [field]: value, ...(field === 'name' && !editingCat ? { slug: slugify(value) } : {}) } : t
      )
    }));
  };

  // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
  // FOTO─ŞRAF FONKS─░YONLARI
  // ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ
  const openNewItem = () => {
    setEditingItem(null);
    setItemForm({
      imageUrl: '', order: items.length, isActive: true, isFeatured: false,
      categoryId: '', locationId: '', serviceId: '',
      translations: LANGUAGES.map(l => ({ language: l, title: '', description: '', altText: '' }))
    });
    setActiveItemLang('TR');
    setShowItemModal(true);
  };

  const openEditItem = (item: any) => {
    setEditingItem(item);
    setItemForm({
      imageUrl: item.imageUrl || '', order: item.order, isActive: item.isActive, isFeatured: item.isFeatured,
      categoryId: item.categoryId || '', locationId: item.locationId || '', serviceId: item.serviceId || '',
      translations: LANGUAGES.map(l => {
        const t = item.translations?.find((tr: any) => tr.language === l);
        return { language: l, title: t?.title || '', description: t?.description || '', altText: t?.altText || '' };
      })
    });
    setActiveItemLang('TR');
    setShowItemModal(true);
  };

  const saveItem = async () => {
    setSaving(true);
    if (!itemForm.imageUrl.trim()) { flash('G├Ârsel URL\'si zorunludur.'); setSaving(false); return; }
    const payload = {
      ...itemForm,
      categoryId: itemForm.categoryId || undefined,
      locationId: itemForm.locationId || undefined,
      serviceId: itemForm.serviceId || undefined,
    };

    let result;
    if (editingItem) {
      result = await updateGalleryItem(editingItem.id, payload);
    } else {
      result = await createGalleryItem(payload);
    }
    if (result.success) {
      flash(editingItem ? 'Foto─şraf g├╝ncellendi!' : 'Foto─şraf eklendi!');
      setShowItemModal(false);
      const fresh = await (await import('@/app/actions/gallery')).getGalleryItems();
      if (fresh.success) setItems(fresh.items);
    } else {
      flash('Hata: ' + (result.error || '─░┼şlem ba┼şar─▒s─▒z.'));
    }
    setSaving(false);
  };

  const removeItem = async (id: string) => {
    if (!confirm('Bu foto─şraf─▒ silmek istedi─şinize emin misiniz?')) return;
    const result = await deleteGalleryItem(id);
    if (result.success) {
      setItems(prev => prev.filter(i => i.id !== id));
      flash('Foto─şraf silindi.');
    }
  };

  const toggleFeatured = async (id: string) => {
    const result = await toggleGalleryItemFeatured(id);
    if (result.success) {
      setItems(prev => prev.map(i => i.id === id ? { ...i, isFeatured: result.isFeatured } : i));
    }
  };

  const moveItem = async (index: number, dir: -1 | 1) => {
    const arr = [...items];
    const target = index + dir;
    if (target < 0 || target >= arr.length) return;
    [arr[index], arr[target]] = [arr[target], arr[index]];
    arr.forEach((it, i) => it.order = i);
    setItems(arr);
    await reorderGalleryItems(arr.map(it => ({ id: it.id, order: it.order })));
  };

  const updateItemTrans = (field: string, value: string) => {
    setItemForm(prev => ({
      ...prev,
      translations: prev.translations.map(t =>
        t.language === activeItemLang ? { ...t, [field]: value } : t
      )
    }));
  };

  // ÔòÉÔòÉÔòÉ Medya Picker ÔòÉÔòÉÔòÉ
  const handleMediaSelect = (url: string) => {
    if (mediaPickerTarget === 'item') setItemForm(p => ({ ...p, imageUrl: url }));
    else if (mediaPickerTarget === 'catImage') setCatForm(p => ({ ...p, image: url }));
    else if (mediaPickerTarget === 'catOg') setCatForm(p => ({ ...p, ogImage: url }));
    setShowMediaPicker(false);
  };

  // ÔòÉÔòÉÔòÉ F─░LTRELEME ÔòÉÔòÉÔòÉ
  const filteredItems = items.filter(item => {
    if (!searchTerm) return true;
    const s = searchTerm.toLowerCase();
    const title = getTrans(item.translations, 'TR', 'title').toLowerCase();
    const alt = getTrans(item.translations, 'TR', 'altText').toLowerCase();
    return title.includes(s) || alt.includes(s) || item.imageUrl?.toLowerCase().includes(s);
  });

  const TABS = [
    { id: 'items' as const, label: 'Galeri Foto─şraflar─▒', icon: ImageIcon, count: items.length },
    { id: 'categories' as const, label: 'Galeri Kategorileri', icon: FolderOpen, count: categories.length },
  ];

  return (
    <div className="space-y-6">
      {/* HEADER */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-serif font-bold text-gray-900">Galeri Y├Ânetimi</h1>
          <p className="text-sm text-gray-500 mt-1">Foto─şraflar─▒, kategorileri ve SEO ayarlar─▒n─▒ y├Ânetin.</p>
        </div>
      </div>

      {/* FLASH MESSAGE */}
      {message && (
        <div className={`px-4 py-3 rounded-xl text-sm font-medium ${message.startsWith('Hata') ? 'bg-red-50 text-red-700 border border-red-200' : 'bg-green-50 text-green-700 border border-green-200'}`}>
          {message}
        </div>
      )}

      {/* TABS */}
      <div className="flex gap-1 bg-gray-100 p-1 rounded-xl">
        {TABS.map(tab => (
          <button key={tab.id} onClick={() => setActiveTab(tab.id)}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold transition-all ${activeTab === tab.id ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}>
            <tab.icon size={16} /> {tab.label}
            <span className="text-xs bg-gray-200 text-gray-600 px-2 py-0.5 rounded-full">{tab.count}</span>
          </button>
        ))}
      </div>

      {/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */}
      {/* FOTO─ŞRAFLAR SEKMES─░                              */}
      {/* ÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉÔòÉ */}
      {activeTab === 'items' && (
        <div className="space-y-4">
          <div className="flex items-center justify-between gap-4">
            <div className="relative flex-1 max-w-sm">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
              <input type="text" value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                placeholder="Ba┼şl─▒k veya alt text ile ara..." className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl text-sm focus:ring-1 focus:ring-[var(--color-rose-500)] focus:outline-none" />
            </div>
            <button onClick={openNewItem}
              className="flex items-center gap-2 bg-[var(--color-rose-600)] text-white px-4 py-2.5 rounded-xl text-sm font-semibold hover:bg-[var(--color-rose-700)] shadow-sm transition-all">
              <Plus size={16} /> Yeni Foto─şraf Ekle
            </button>
          </div>

          {filteredItems.length === 0 ? (
            <div className="text-center py-16 bg-white rounded-2xl border border-gray-200">
              <ImageIcon className="mx-auto text-gray-300 mb-4" size={48} />
              <p className="text-gray-500 font-medium">Hen├╝z foto─şraf eklenmemi┼ş.</p>
              <button onClick={openNewItem} className="mt-4 text-[var(--color-rose-600)] font-semibold text-sm hover:underline">
                ─░lk foto─şraf─▒ ekle ÔåÆ
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
              {filteredItems.map((item: any, idx: number) => (
                <div key={item.id} className={`bg-white rounded-2xl border overflow-hidden group relative transition-all ${!item.isActive ? 'opacity-50' : ''} ${item.isFeatured ? 'border-yellow-400 ring-1 ring-yellow-200' : 'border-gray-200'}`}>
                  {/* Thumbnail */}
                  <div className="aspect-square relative overflow-hidden bg-gray-100">
                    <Image width={800} height={800} src={item.imageUrl} alt={getTrans(item.translations, 'TR', 'altText') || ''} className="w-full h-full object-cover" />
                    {/* Overlay */}
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                      <button onClick={() => openEditItem(item)} className="p-2 bg-white/90 rounded-full hover:bg-white"><Edit size={14} /></button>
                      <button onClick={() => toggleFeatured(item.id)} className="p-2 bg-white/90 rounded-full hover:bg-white">
                        {item.isFeatured ? <StarOff size={14} className="text-yellow-500" /> : <Star size={14} />}
                      </button>
                      <button onClick={() => removeItem(item.id)} className="p-2 bg-white/90 rounded-full hover:bg-white text-red-500"><Trash2 size={14} /></button>
                    </div>
                    {/* Badges */}
                    {item.isFeatured && <span className="absolute top-2 left-2 bg-yellow-400 text-yellow-900 text-[10px] font-bold px-2 py-0.5 rounded-full">Ôİà ├ûNE ├çIKAN</span>}
                    {!item.isActive && <span className="absolute top-2 right-2 bg-red-100 text-red-600 text-[10px] font-bold px-2 py-0.5 rounded-full">PAS─░F</span>}
                  </div>
                  {/* Info */}
                  <div className="p-3 space-y-1">
                    <p className="text-xs font-semibold text-gray-900 truncate">{getTrans(item.translations, 'TR', 'title') || 'Ba┼şl─▒ks─▒z'}</p>
                    <p className="text-[10px] text-gray-400 truncate">{getTrans(item.translations, 'TR', 'altText') || '-'}</p>
                    <div className="flex items-center justify-between">
                      <span className="text-[10px] text-[var(--color-rose-600)] font-medium">
                        {item.category ? getTrans(item.category.translations, 'TR', 'name') : 'Kategorisiz'}
                      </span>
                      <div className="flex gap-1">
                        <button onClick={() => moveItem(idx, -1)} disabled={idx === 0} className="p-1 text-gray-400 hover:text-gray-600 disabled:opacity-30"><ChevronUp size={12} /></button>
