"use client";

import { useState } from 'react';
import { updateLeadStatus, updateLeadNotes } from '@/app/actions/lead';
import { LeadStatus } from '@prisma/client';
import { 
  Phone, 
  Mail, 
  Calendar, 
  MessageSquare, 
  Tag, 
  Clock, 
  CheckCircle, 
  FileText, 
  Check, 
  AlertCircle 
} from 'lucide-react';

interface LeadItem {
  id: string;
  name: string;
  phone: string | null;
  email: string | null;
  source: string | null;
  message: string | null;
  status: LeadStatus;
  notes: string | null;
  createdAt: string;
}

interface LeadsClientProps {
  initialLeads: LeadItem[];
}

export default function LeadsClient({ initialLeads }: LeadsClientProps) {
  const [leads, setLeads] = useState<LeadItem[]>(initialLeads);
  const [activeTab, setActiveTab] = useState<string>('ALL');
  const [editingNotesId, setEditingNotesId] = useState<string | null>(null);
  const [tempNotes, setTempNotes] = useState<string>('');
  const [loadingId, setLoadingId] = useState<string | null>(null);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const statusConfig = {
    PENDING: { label: 'Beklemede', color: 'bg-yellow-50 text-yellow-700 border-yellow-200' },
    IN_PROGRESS: { label: '─░┼şlemde', color: 'bg-blue-50 text-blue-700 border-blue-200' },
    CONTACTED: { label: 'Ula┼ş─▒ld─▒', color: 'bg-indigo-50 text-indigo-700 border-indigo-200' },
    CONVERTED: { label: 'D├Ân├╝┼şt├╝', color: 'bg-green-50 text-green-700 border-green-200' },
  };

  const tabs = [
    { key: 'ALL', label: 'T├╝m Talepler' },
    { key: 'PENDING', label: 'Bekleyenler' },
    { key: 'IN_PROGRESS', label: '─░┼şlemdekiler' },
    { key: 'CONTACTED', label: 'Ula┼ş─▒lanlar' },
    { key: 'CONVERTED', label: 'Kazan─▒lanlar' },
  ];

  const filteredLeads = leads.filter(lead => {
    if (activeTab === 'ALL') return true;
    return lead.status === activeTab;
  });

  const handleStatusChange = async (id: string, newStatus: LeadStatus) => {
    setLoadingId(id);
    const result = await updateLeadStatus(id, newStatus);
    setLoadingId(null);

    if (result.success) {
      setLeads(prev => prev.map(lead => lead.id === id ? { ...lead, status: newStatus } : lead));
      showFeedback('success', 'Talep durumu ba┼şar─▒yla g├╝ncellendi.');
    } else {
      showFeedback('error', result.error || 'Durum g├╝ncellenirken bir hata olu┼ştu.');
    }
  };

  const handleNotesEditStart = (id: string, currentNotes: string | null) => {
    setEditingNotesId(id);
    setTempNotes(currentNotes || '');
  };

  const handleNotesSave = async (id: string) => {
    setLoadingId(id);
    const result = await updateLeadNotes(id, tempNotes);
    setLoadingId(null);

    if (result.success) {
      setLeads(prev => prev.map(lead => lead.id === id ? { ...lead, notes: tempNotes } : lead));
      setEditingNotesId(null);
      showFeedback('success', 'Not ba┼şar─▒yla kaydedildi.');
    } else {
      showFeedback('error', result.error || 'Not kaydedilirken bir hata olu┼ştu.');
    }
  };

  const showFeedback = (type: 'success' | 'error', text: string) => {
    setMessage({ type, text });
    setTimeout(() => setMessage(null), 3000);
  };

  return (
    <div className="space-y-6">
      {/* Feedback Message */}
      {message && (
        <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 px-4 py-3 rounded-xl shadow-lg border transition-all duration-300 ${
          message.type === 'success' ? 'bg-green-50 text-green-800 border-green-200' : 'bg-red-50 text-red-800 border-red-200'
        }`}>
          {message.type === 'success' ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-medium">{message.text}</span>
        </div>
      )}

      {/* Tabs */}
      <div className="flex border-b border-gray-200 overflow-x-auto pb-px">
        {tabs.map((tab) => (
          <button
            key={tab.key}
            onClick={() => setActiveTab(tab.key)}
            className={`whitespace-nowrap pb-4 px-6 font-medium text-sm border-b-2 transition-all duration-200 ${
              activeTab === tab.key
                ? 'border-[var(--color-rose-600)] text-[var(--color-rose-700)]'
                : 'border-transparent text-gray-500 hover:text-gray-900 hover:border-gray-300'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Leads List */}
      <div className="grid grid-cols-1 gap-6">
        {filteredLeads.length === 0 ? (
          <div className="bg-white border border-gray-100 rounded-2xl p-12 text-center">
            <Clock className="mx-auto text-gray-300 mb-4" size={48} />
            <p className="text-gray-500 font-medium">Bu kategoride hen├╝z talep bulunmuyor.</p>
          </div>
        ) : (
          filteredLeads.map((lead) => (
            <div key={lead.id} className="bg-white border border-gray-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow duration-200 p-6 flex flex-col md:flex-row gap-6 justify-between">
              {/* Left Column: M├╝┼şteri Bilgileri */}
              <div className="flex-1 space-y-4">
                <div className="flex flex-wrap items-center gap-3">
                  <h3 className="text-lg font-bold text-gray-900">{lead.name}</h3>
                  <span className={`text-xs px-2.5 py-1 rounded-full font-semibold border ${statusConfig[lead.status].color}`}>
                    {statusConfig[lead.status].label}
                  </span>
                  {lead.source && (
                    <span className="text-xs bg-gray-100 text-gray-600 px-2 py-0.5 rounded border border-gray-200">
                      Kaynak: {lead.source}
                    </span>
                  )}
                </div>

