  // G├╝venlik Kontrol├╝
  if (!token || token.value !== 'authenticated') {
    redirect(`/admin/login`);
  }

  // Veritaban─▒ndan silinmemi┼ş ┼şubeleri ├ğek
  const locations = await prisma.location.findMany({
    where: { isDeleted: false },
    include: { workingHours: true },
