    seoTitle: l.seoTitle,
    seoDesc: l.seoDesc,
    canonical: l.canonical,
    ogTitle: l.ogTitle,
    ogDesc: l.ogDesc,
    ogImage: l.ogImage,
    workingHours: l.workingHours.map(wh => ({
      id: wh.id,
      dayOfWeek: wh.dayOfWeek,
      openTime: wh.openTime,
      closeTime: wh.closeTime,
      isClosed: wh.isClosed,
      breakStart: wh.breakStart,
      breakEnd: wh.breakEnd,
