                          <a 
                            href={tr.url} 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="p-1.5 text-gray-400 hover:text-rose-600 hover:bg-rose-50 rounded-lg transition-all cursor-pointer"
                            title="Sayfay─▒ ├ûnizle"
                          >
                            <Eye size={14} />
                          </a>
                        )}
                        <Link
                          href={`/admin/menus/${item.id}`}
