                    className={`flex-1 py-3 text-[11px] font-bold uppercase tracking-wider transition-all cursor-pointer relative ${
                      activeLang === lang 
                        ? 'text-[var(--color-rose-500)] bg-[var(--color-rose-500)]/5' 
