import { cookies } from 'next/headers';
import { redirect } from 'next/navigation';
import { prisma } from '@/lib/prisma';
import { 
  Calendar, 
  Clock, 
  TrendingUp, 
  TrendingDown, 
  Users, 
  Scissors, 
  DollarSign, 
  CalendarDays,
  Sparkles
} from 'lucide-react';
import AdminShell from '@/components/admin/AdminShell';
import AppointmentsClient from './AppointmentsClient';

export default async function AdminDashboard() {
  const cookieStore = await cookies();
  const token = cookieStore.get('admin_token');



  // G├╝venlik Kontrol├╝
  if (!token || token.value !== 'authenticated') {
    redirect(`/admin/login`);
  }

  // Tarihleri hesaplayal─▒m
  const todayStart = new Date();
  todayStart.setHours(0, 0, 0, 0);

  const todayEnd = new Date();
  todayEnd.setHours(23, 59, 59, 999);

  // Bu haftan─▒n ba┼ş─▒ (Pazartesi) ve sonu (Pazar)
  const startOfWeek = new Date();
  const day = startOfWeek.getDay();
  const diff = startOfWeek.getDate() - day + (day === 0 ? -6 : 1);
  startOfWeek.setDate(diff);
  startOfWeek.setHours(0, 0, 0, 0);

  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);
  endOfWeek.setHours(23, 59, 59, 999);

  // Veritaban─▒ sorgular─▒n─▒ yapal─▒m
  let upcomingAppointments: any[] = [];
  let todayApptsCount = 0;
  let weekApptsCount = 0;
  let allAppointmentsForStats: any[] = [];
  let transactions: any[] = [];

  try {
    // 1. Gelecek randevular (Bug├╝n dahil)
    upcomingAppointments = await prisma.appointment.findMany({
      where: {
        date: {
          gte: todayStart,
        }
      },
      orderBy: [
        { date: 'desc' },
        { startTime: 'desc' }
      ],
      include: {
        service: {
          include: { translations: { where: { language: 'TR' } } }
        },
        staff: true,
        location: true,
        statusHistory: {
          orderBy: { createdAt: 'desc' }
        }
      }
    });

    // 2. Bug├╝n├╝n randevu say─▒s─▒
    todayApptsCount = await prisma.appointment.count({
      where: {
        date: {
          gte: todayStart,
          lte: todayEnd
        }
      }
    });

    // 3. Bu haftan─▒n randevu say─▒s─▒
    weekApptsCount = await prisma.appointment.count({
      where: {
        date: {
          gte: startOfWeek,
          lte: endOfWeek
        }
      }
    });

    // 4. ─░statistik hesab─▒ i├ğin t├╝m onayl─▒ ve tamamlanm─▒┼ş randevular─▒ ├ğek
    allAppointmentsForStats = await prisma.appointment.findMany({
      where: {
        status: {
          in: ['CONFIRMED', 'COMPLETED']
        }
      },
      include: {
        service: {
          include: { translations: { where: { language: 'TR' } } }
        },
        staff: true
      }
    });

    // 5. Finansal k├ór i├ğin t├╝m muhasebe i┼şlemlerini ├ğek
    transactions = await prisma.transaction.findMany();
  } catch (error) {
    console.error("Dashboard veri ├ğekme hatas─▒:", error);
  }

  // A) Pop├╝ler Hizmet Hesaplama
  const serviceCounts: Record<string, { name: string; count: number }> = {};
  allAppointmentsForStats.forEach((appt) => {
    const serviceId = appt.serviceId;
    const name = appt.service?.translations[0]?.name || 'Bilinmeyen Hizmet';
    if (!serviceCounts[serviceId]) {
      serviceCounts[serviceId] = { name, count: 0 };
    }
    serviceCounts[serviceId].count += 1;
  });
  const popularService = Object.values(serviceCounts).sort((a, b) => b.count - a.count)[0]?.name || 'Veri Yok';

  // B) Yo─şun Personel Hesaplama
  const staffCounts: Record<string, { name: string; count: number }> = {};
  allAppointmentsForStats.forEach((appt) => {
