    EN: { h1Title: 'Our Visual Art Gallery', introText: 'Fascinating transformations and our trendiest nail art & lash applications.', seoTitle: 'Photo Gallery | Gel Polish and Nail Art', seoDesc: 'High-quality before/after images of acrylic nails, nail art, and eyelash extensions.', headerImage: 'https://images.unsplash.com/photo-1588693959600-0e42f9e4220b?q=80&w=2070&auto=format&fit=crop' },
    DE: { h1Title: 'Unsere Kunstgalerie', introText: 'Faszinierende Verwandlungen und trendige Nail Art Anwendungen.', seoTitle: 'Fotogalerie | Gellack und Nail Art', seoDesc: 'Hochwertige Vorher-/Nachher-Bilder von Acryln├ñgeln und Wimpernverl├ñngerungen.', headerImage: 'https://images.unsplash.com/photo-1588693959600-0e42f9e4220b?q=80&w=2070&auto=format&fit=crop' },
    RU: { h1Title: 'ºØº░ªêº░ ºôº░º╗ºÁªÇºÁªÅ', introText: 'ºùº░º▓º¥ªÇº░ºÂº©º▓º░ªÄªëº©ºÁ º┐ªÇºÁº¥º▒ªÇº░ºÂºÁº¢º©ªÅ º© º¢º░ªêº© ªéªÇºÁº¢º┤º¥º▓ªïºÁ ªÇº░º▒º¥ªéªï.', seoTitle: 'ºñº¥ªéº¥º│º░º╗ºÁªÇºÁªÅ | ºôºÁº╗ªî-º╗º░º║ º© ºöº©ºÀº░º╣º¢', seoDesc: 'ºÜº░ªçºÁªüªéº▓ºÁº¢º¢ªïºÁ ªäº¥ªéº¥ º┤º¥/º┐º¥ªüº╗ºÁ º¢º░ªÇº░ªëº©º▓º░º¢º©ªÅ º¢º¥º│ªéºÁº╣, º¢ºÁº╣º╗-º░ªÇªéº░ º© ªÇºÁªüº¢º©ªå.', headerImage: 'https://images.unsplash.com/photo-1588693959600-0e42f9e4220b?q=80&w=2070&auto=format&fit=crop' }
