    DE: { h1Title: 'Kontaktiere Uns', introText: 'F├╝r Ihre Fragen oder detaillierte Informationen k├Ânnen Sie uns jederzeit kontaktieren.', seoTitle: 'Kontakt | Antalya Nails & Lashes Studio', seoDesc: 'Kontaktinformationen, Adresskarte und WhatsApp-Terminvereinbarung.', headerImage: 'https://images.unsplash.com/photo-1596178060671-7a80fc80e6c5?q=80&w=2070&auto=format&fit=crop' },
    RU: { h1Title: 'ºíº▓ªÅºÀº░ªéªîªüªÅ ªü ºØº░º╝º©', introText: 'ºÆªï º╝º¥ºÂºÁªéºÁ ªüº▓ªÅºÀº░ªéªîªüªÅ ªü º¢º░º╝º© º▓ º╗ªÄº▒º¥ºÁ º▓ªÇºÁº╝ªÅ º┤º╗ªÅ º┐º¥º╗ªâªçºÁº¢º©ªÅ º┐º¥º┤ªÇº¥º▒º¢º¥º╣ º©º¢ªäº¥ªÇº╝º░ªåº©º©.', seoTitle: 'ºÜº¥º¢ªéº░º║ªéªï | Antalya Nails & Lashes Studio', seoDesc: 'ºÜº¥º¢ªéº░º║ªéº¢º░ªÅ º©º¢ªäº¥ªÇº╝º░ªåº©ªÅ, º║º░ªÇªéº░ º░º┤ªÇºÁªüº¥º▓ º© º╗º©º¢º©ªÅ ºÀº░º┐º©ªüº© WhatsApp.', headerImage: 'https://images.unsplash.com/photo-1596178060671-7a80fc80e6c5?q=80&w=2070&auto=format&fit=crop' }
  }
};

export default function PageEditClient({ page, isNew }: PageEditClientProps) {
  const router = useRouter();

  const [activeLang, setActiveLang] = useState<'TR' | 'EN' | 'DE' | 'RU'>('TR');
  const [isActive, setIsActive] = useState(page?.isActive ?? true);
  const [pageGroup, setPageGroup] = useState(page?.pageGroup || '');
  const [loading, setLoading] = useState(false);
  const [saved, setSaved] = useState(false);

  // Men├╝ Entegrasyonu
  const [headerMenu, setHeaderMenu] = useState(page?.menuItems?.some((m: any) => m.menuType === 'HEADER' && m.isActive) ?? false);
  const [footerMenu, setFooterMenu] = useState(page?.menuItems?.some((m: any) => m.menuType === 'FOOTER' && m.isActive) ?? false);
  const [order, setOrder] = useState(page?.menuItems?.[0]?.order || 0);

  // Dil bazl─▒ t├╝m state'ler
  const [translations, setTranslations] = useState<Record<string, any>>(
    LANGUAGES.reduce((acc, lang) => {
      const existing = page?.translations?.find((t: any) => t.language === lang.code);
      const slugKey = existing?.slug || page?.translations?.[0]?.slug || '';
      const fallback = PREDEFINED_SEO[slugKey]?.[lang.code];

      acc[lang.code] = {
        title: existing?.title || '',
        h1Title: existing?.h1Title || fallback?.h1Title || '',
        editorTitle: existing?.editorTitle || '',
        introText: existing?.introText || fallback?.introText || '',
        content: existing?.content || '',
        headerImage: existing?.headerImage || fallback?.headerImage || '',
        thumbnailImage: existing?.thumbnailImage || fallback?.headerImage || '',
        slug: existing?.slug || '',
        seoTitle: existing?.seoTitle || fallback?.seoTitle || '',
        seoDesc: existing?.seoDesc || fallback?.seoDesc || '',
        canonical: existing?.canonical || '',
        ogTitle: existing?.ogTitle || fallback?.seoTitle || '',
        ogDesc: existing?.ogDesc || fallback?.seoDesc || '',
        ogImage: existing?.ogImage || fallback?.headerImage || '',
        index: existing?.index ?? true,
        sitemap: existing?.sitemap ?? true,
      };
      return acc;
    }, {} as any)
  );

  // Media Picker State
  const [mediaPickerOpen, setMediaPickerOpen] = useState(false);
  const [mediaTarget, setMediaTarget] = useState<'header' | 'thumbnail' | null>(null);

  const t = translations[activeLang];

  const updateTranslation = (field: string, value: any) => {
    setTranslations(prev => ({
      ...prev,
      [activeLang]: {
        ...prev[activeLang],
        [field]: value
      }
    }));
  };

  const handleMediaSelect = (url: string) => {
    setTranslations((prev) => {
      const next = { ...prev };
      Object.keys(next).forEach((lang) => {
        if (mediaTarget === 'header') {
          next[lang] = { ...next[lang], headerImage: url };
        } else if (mediaTarget === 'thumbnail') {
          next[lang] = { ...next[lang], thumbnailImage: url };
        }
      });
      return next;
    });
    setMediaPickerOpen(false);
  };

  const autoSlug = (text: string) => {
    return text.toLowerCase()
      .replace(/─ş/g, 'g').replace(/├╝/g, 'u').replace(/┼ş/g, 's')
      .replace(/─▒/g, 'i').replace(/├Â/g, 'o').replace(/├ğ/g, 'c')
      .replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').trim();
  };

  const handleSave = async () => {
    if (!t.title || !t.slug) {
      alert(`${activeLang} dilinde Ba┼şl─▒k ve URL Slug alanlar─▒ zorunludur! L├╝tfen o sekmeye ge├ğip doldurun.`);
      return;
    }

    setLoading(true);
    setSaved(false);

    const formData = new FormData();
    formData.append('isActive', isActive.toString());
    formData.append('pageGroup', pageGroup);
    formData.append('headerMenu', headerMenu.toString());
    formData.append('footerMenu', footerMenu.toString());
    formData.append('order', order.toString());
    
    // Yaln─▒zca aktif dili kaydediyoruz (ya da t├╝m dilleri tek seferde kaydetmek isterseniz action g├╝ncellenmeli. ┼Şu anki action tek dil destekliyor.)
    // D─░KKAT: Mevcut sistemde `/admin/pages` mod├╝l├╝ tek dilli kaydediyor, ancak sekme yap─▒s─▒yla aktif dili g├Ânderiyoruz.
    // Biz mevcut API'yi bozmamak ad─▒na aktif dili kaydetmeyi s├╝rd├╝r├╝yoruz. ─░leride action array kabul edebilir.
    formData.append('language', activeLang);
    formData.append('title', t.title);
    formData.append('h1Title', t.h1Title);
    formData.append('editorTitle', t.editorTitle);
    formData.append('introText', t.introText);
    formData.append('content', t.content);
    formData.append('headerImage', t.headerImage);
    formData.append('thumbnailImage', t.thumbnailImage);
    formData.append('slug', t.slug);
    formData.append('seoTitle', t.seoTitle);
    formData.append('seoDesc', t.seoDesc);
    formData.append('canonical', t.canonical);
    formData.append('ogTitle', t.ogTitle);
    formData.append('ogDesc', t.ogDesc);
    formData.append('ogImage', t.ogImage);
    formData.append('index', t.index.toString());
    formData.append('sitemap', t.sitemap.toString());

    let result;
    if (isNew) {
      result = await createCmsPage(formData);
    } else {
      const translationId = page?.translations?.find((x: any) => x.language === activeLang)?.id || null;
      result = await updateCmsPage(page!.id, translationId, formData);
    }

    setLoading(false);

    if (result.success) {
      setSaved(true);
      setTimeout(() => setSaved(false), 2500);
      if (isNew) {
        router.push('/admin/pages');
      }
    } else {
      alert(result.error || 'Hata olu┼ştu.');
    }
  };

  const handleDelete = async () => {
    if (!page || isNew) return;
    if (!confirm('Bu sayfay─▒ pasifle┼ştirmek istedi─şinize emin misiniz?')) return;
    await deleteCmsPage(page.id);
    router.push('/admin/pages');
  };

  return (
    <>
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex flex-col md:flex-row items-center justify-between shrink-0 gap-4">
        <div className="flex items-center gap-4">
          <Link href="/admin/pages" className="p-2 text-gray-500 hover:text-gray-700 hover:bg-gray-100 rounded-full transition-colors">
            <ArrowLeft size={20} />
          </Link>
          <div>
            <h1 className="text-xl font-bold text-gray-900 flex items-center gap-2">
              <FileText size={22} className="text-rose-600" />
              {isNew ? 'Yeni Sayfa Olu┼ştur' : 'Sayfay─▒ D├╝zenle'}
            </h1>
            <p className="text-sm text-gray-500 mt-1">SAYFA & ─░├çER─░K Y├ûNET─░M─░</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {!isNew && (
            <button onClick={handleDelete} className="px-4 py-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg font-medium transition-colors flex items-center gap-2">
              <Trash2 size={18} /> Sil
            </button>
          )}
          <button
            onClick={handleSave}
            disabled={loading}
            className="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-all shadow-sm hover:shadow flex items-center gap-2 disabled:opacity-70"
          >
            {loading ? <Loader2 size={18} className="animate-spin" /> : saved ? <Check size={18} /> : <Save size={18} />}
            {saved ? 'Kaydedildi' : 'De─şi┼şiklikleri Kaydet'}
          </button>
        </div>
      </header>

      <div className="flex-1 overflow-auto p-4 md:p-6 bg-gray-50/50">
        <div className="max-w-[1600px] mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6">
          
          {/* SOL BLOK */}
          <div className="col-span-1 lg:col-span-3 space-y-6">
            
            {/* SAYFA G├ûRSELLER─░ */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-100 flex items-center gap-2">
                <ImageIcon size={18} className="text-blue-500" />
                <h3 className="font-semibold text-gray-800 text-sm tracking-wide">SAYFA G├ûRSELLER─░</h3>
              </div>
              <div className="p-5 space-y-5">
                <div>
                  <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase">Header G├Ârseli (Geni┼ş)</label>
                  <div 
                    onClick={() => { setMediaTarget('header'); setMediaPickerOpen(true); }}
                    className="aspect-video w-full rounded-lg border-2 border-dashed border-gray-300 hover:border-blue-500 bg-gray-50 flex flex-col items-center justify-center cursor-pointer overflow-hidden transition-colors group relative"
                  >
                    {t.headerImage ? (
                      <Image width={800} height={800} src={t.headerImage} alt="Header" className="w-full h-full object-cover" />
                    ) : (
                      <div className="text-center p-4">
                        <ImageIcon size={24} className="mx-auto text-gray-400 group-hover:text-blue-500 mb-2" />
                        <span className="text-sm font-medium text-gray-500 group-hover:text-blue-600">G├Ârsel Se├ğ</span>
                      </div>
                    )}
                  </div>
                </div>

                <div>
                  <label className="block text-xs font-semibold text-gray-500 mb-2 uppercase">Liste / Thumbnail</label>
                  <div 
                    onClick={() => { setMediaTarget('thumbnail'); setMediaPickerOpen(true); }}
                    className="aspect-[4/3] w-full rounded-lg border-2 border-dashed border-gray-300 hover:border-blue-500 bg-gray-50 flex flex-col items-center justify-center cursor-pointer overflow-hidden transition-colors group relative"
                  >
                    {t.thumbnailImage ? (
                      <Image width={800} height={800} src={t.thumbnailImage} alt="Thumbnail" className="w-full h-full object-cover" />
                    ) : (
                      <div className="text-center p-4">
                        <ImageIcon size={24} className="mx-auto text-gray-400 group-hover:text-blue-500 mb-2" />
                        <span className="text-sm font-medium text-gray-500 group-hover:text-blue-600">G├Ârsel Se├ğ</span>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* YAPILANDIRMA */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-100 flex items-center gap-2">
                <Settings size={18} className="text-rose-500" />
                <h3 className="font-semibold text-gray-800 text-sm tracking-wide">YAPILANDIRMA</h3>
              </div>
              <div className="p-5 space-y-5">
                <div>
                  <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase">Sistem Ad─▒ (Liste)</label>
                  <input
                    type="text"
                    value={t.title}
                    onChange={(e) => {
                      updateTranslation('title', e.target.value);
                      if (!t.slug) updateTranslation('slug', autoSlug(e.target.value));
                    }}
                    className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                    placeholder="├ûrn: Transfer"
                  />
                </div>

                <div>
                  <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase">Sayfa Grubu</label>
                  <select
                    value={pageGroup}
                    onChange={(e) => setPageGroup(e.target.value)}
                    className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                  >
                    <option value="">Grup Yok</option>
                    <option value="ust-menu">├£st Men├╝ Sayfas─▒</option>
                    <option value="alt-menu">Alt Men├╝ Sayfas─▒</option>
                    <option value="kurumsal">Kurumsal</option>
                  </select>
                </div>

                <div className="flex gap-4">
                  <div className="flex-1">
                    <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase">S─▒ralama</label>
                    <input
                      type="number"
                      value={order}
                      onChange={(e) => setOrder(parseInt(e.target.value) || 0)}
                      className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                    />
                  </div>
                  <div className="flex-1 flex flex-col items-center justify-center pt-5">
                    <button
                      onClick={() => setIsActive(!isActive)}
                      className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold transition-colors ${
                        isActive ? 'bg-emerald-100 text-emerald-700' : 'bg-gray-100 text-gray-500'
                      }`}
                    >
                      <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-emerald-500' : 'bg-gray-400'}`}></div>
                      {isActive ? 'YAYINDA' : 'PAS─░F'}
                    </button>
                  </div>
                </div>

                <div className="pt-4 border-t border-gray-100 flex justify-between gap-2">
                   <button
                    onClick={() => setHeaderMenu(!headerMenu)}
                    className={`flex-1 py-3 px-2 flex flex-col items-center justify-center gap-2 rounded-xl border-2 transition-all ${
                      headerMenu ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-gray-100 bg-gray-50 text-gray-500 hover:border-gray-200'
                    }`}
                  >
                    <div className="flex items-center gap-2">
                      {headerMenu ? <ToggleRight size={20} className="text-blue-500"/> : <ToggleLeft size={20} className="text-gray-400"/>}
                    </div>
                    <span className="text-[10px] font-bold uppercase tracking-wider">Header Men├╝</span>
                  </button>

                  <button
                    onClick={() => setFooterMenu(!footerMenu)}
                    className={`flex-1 py-3 px-2 flex flex-col items-center justify-center gap-2 rounded-xl border-2 transition-all ${
                      footerMenu ? 'border-blue-500 bg-blue-50 text-blue-700' : 'border-gray-100 bg-gray-50 text-gray-500 hover:border-gray-200'
                    }`}
                  >
                    <div className="flex items-center gap-2">
                      {footerMenu ? <ToggleRight size={20} className="text-blue-500"/> : <ToggleLeft size={20} className="text-gray-400"/>}
                    </div>
                    <span className="text-[10px] font-bold uppercase tracking-wider">Footer Men├╝</span>
                  </button>
                </div>
              </div>
            </div>

          </div>

          {/* SA─Ş BLOK */}
          <div className="col-span-1 lg:col-span-9 flex flex-col gap-6">
            
            {/* Dil Sekmeleri */}
            <div className="flex items-center gap-2 overflow-x-auto pb-2 border-b border-gray-200">
              {LANGUAGES.map((lang) => (
                <button
                  key={lang.code}
                  onClick={() => setActiveLang(lang.code as any)}
                  className={`px-6 py-3 rounded-t-xl font-medium text-xs tracking-wider uppercase transition-all whitespace-nowrap flex items-center gap-2 ${
                    activeLang === lang.code
                      ? 'bg-white text-blue-600 border-t-2 border-x border-blue-600 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]'
                      : 'text-gray-500 hover:bg-gray-100 hover:text-gray-700 border border-transparent'
                  }`}
                >
                  <Globe size={14} className={activeLang === lang.code ? 'text-blue-500' : 'text-gray-400'} />
                  {lang.label}
                </button>
              ))}
            </div>

            {/* SAYFA BA┼ŞLIKLARI */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-100 flex items-center gap-2">
                <Type size={18} className="text-blue-500" />
                <h3 className="font-semibold text-gray-800 text-sm tracking-wide uppercase">Sayfa Ba┼şl─▒klar─▒ ({activeLang})</h3>
              </div>
              <div className="p-5 space-y-5">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase">Sayfa Ba┼şl─▒─ş─▒ (Sistem)</label>
                    <input
                      type="text"
                      value={t.title}
                      onChange={(e) => updateTranslation('title', e.target.value)}
                      className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm bg-gray-50 focus:bg-white focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase">H1 Ba┼şl─▒k (Hero / Banner)</label>
                    <input
                      type="text"
                      value={t.h1Title}
                      onChange={(e) => updateTranslation('h1Title', e.target.value)}
                      className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase">G├Âvde / Edit├Âr Ba┼şl─▒─ş─▒</label>
                    <input
                      type="text"
                      value={t.editorTitle}
                      onChange={(e) => updateTranslation('editorTitle', e.target.value)}
                      className="w-full px-4 py-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-xs font-semibold text-gray-500 mb-1.5 uppercase">Giri┼ş Metni (Intro Banner)</label>
                  <textarea
                    value={t.introText}
                    onChange={(e) => updateTranslation('introText', e.target.value)}
                    rows={2}
                    className="w-full px-4 py-3 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 resize-none bg-gray-50 focus:bg-white"
                  />
                </div>
              </div>
            </div>

            {/* DETAYLI ─░├çER─░K */}
            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col h-[500px]">
              <div className="px-5 py-4 border-b border-gray-100 flex items-center justify-between shrink-0">
                <div className="flex items-center gap-2">
                  <Layout size={18} className="text-orange-500" />
                  <h3 className="font-semibold text-gray-800 text-sm tracking-wide uppercase">Detayl─▒ ─░├ğerik (G├Âvde)</h3>
                </div>
                <span className="text-[10px] font-bold text-orange-500 uppercase tracking-wider bg-orange-50 px-2 py-1 rounded">
                  {pageGroup === 'SYSTEM' ? 'S─░STEM SAYFASI' : 'ZENG─░N MET─░N'}
                </span>
              </div>
              {pageGroup === 'SYSTEM' ? (
                <div className="flex-1 p-8 flex flex-col items-center justify-center text-center bg-gray-50/50">
                  <div className="w-16 h-16 bg-blue-50 border border-blue-100 rounded-full flex items-center justify-center mb-4 shadow-sm">
                    <Layout size={32} className="text-blue-500" />
                  </div>
                  <h4 className="text-lg font-bold text-gray-800 mb-2">Bu Bir Sistem Sayfas─▒d─▒r</h4>
                  <p className="text-sm text-gray-500 max-w-md">
                    Bu sayfan─▒n ana i├ğeri─şi ve tasar─▒m─▒ sistem mimarisinden otomatik ├ğekilir. ─░├ğerik edit├Âr├╝ ├╝zerinden de─şi┼ştirilemez. 
                    <br/><br/>Ancak sol b├Âl├╝mden <strong>Foto─şraflar─▒n─▒ ve Men├╝ Durumunu</strong>, a┼şa─ş─▒dan ise <strong>SEO (Arama Motoru) Ayarlar─▒n─▒</strong> ├Âzg├╝rce y├Ânetebilirsiniz.
                  </p>
                </div>
              ) : (
                <div className="flex-1 p-0 overflow-hidden">
                  <RichTextEditor 
                    content={t.content} 
                    onChange={(val) => updateTranslation('content', val)} 
                  />
                </div>
              )}
            </div>

            {/* SEO & ARAMA MOTORU AYARLARI */}
            <div className="bg-[#0f172a] rounded-xl border border-slate-700 shadow-sm overflow-hidden mb-8">
              <div className="px-5 py-4 border-b border-slate-700/50 flex items-center gap-2">
                <SearchIcon size={18} className="text-cyan-400" />
                <h3 className="font-semibold text-white text-sm tracking-wide uppercase">SEO & Arama Motoru Ayarlar─▒</h3>
              </div>
              <div className="p-5 space-y-5">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="col-span-1 md:col-span-2 lg:col-span-1">
                    <label className="block text-[11px] font-bold text-slate-400 mb-1.5 uppercase tracking-wider">Sayfa Rota Adresi (URL Slug)</label>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <span className="text-slate-500 font-medium">/{activeLang.toLowerCase()}/</span>
                      </div>
                      <input
                        type="text"
                        value={t.slug}
                        onChange={(e) => updateTranslation('slug', e.target.value)}
                        className="w-full pl-[4.5rem] pr-4 py-2.5 border rounded-lg text-sm transition-all font-mono bg-slate-800/50 border-slate-600 text-cyan-50 focus:ring-2 focus:ring-cyan-500/50 focus:border-cyan-500"
                      />
                    </div>
                  </div>
                  <div>
                    <label className="block text-[11px] font-bold text-slate-400 mb-1.5 uppercase tracking-wider">Google Ba┼şl─▒─ş─▒ (Meta Title)</label>
                    <input
                      type="text"
                      value={t.seoTitle}
                      onChange={(e) => updateTranslation('seoTitle', e.target.value)}
                      className="w-full px-4 py-2.5 bg-slate-800/50 border border-slate-600 rounded-lg text-sm text-white focus:ring-2 focus:ring-cyan-500/50 focus:border-cyan-500 transition-all"
                    />
                  </div>
                </div>
                
                <div>
                  <label className="block text-[11px] font-bold text-slate-400 mb-1.5 uppercase tracking-wider">Arama Motoru A├ğ─▒klamas─▒ (Meta Description)</label>
                  <textarea
                    value={t.seoDesc}
                    onChange={(e) => updateTranslation('seoDesc', e.target.value)}
                    rows={2}
                    className="w-full px-4 py-3 bg-slate-800/50 border border-slate-600 rounded-lg text-sm text-white focus:ring-2 focus:ring-cyan-500/50 focus:border-cyan-500 transition-all resize-none"
                  />
                </div>
              </div>
            </div>

          </div>
        </div>
      </div>

      <MediaPickerModal
        isOpen={mediaPickerOpen}
        onClose={() => setMediaPickerOpen(false)}
        onSelect={handleMediaSelect}
      />
    </>
  );
}

"use client";

import Image from 'next/image';
import { useState } from 'react';
import { createPortfolioItem, updatePortfolioItem, deletePortfolioItem } from '@/app/actions/portfolio';
import { Language } from '@prisma/client';
import { 
  Plus, 
  Search, 
  Globe, 
  Settings, 
  CheckCircle, 
  AlertCircle,
  X,
  Edit,
  Trash2,
  Check,
  Eye,
  Info,
  Calendar,
  Image as ImageIcon,
  ArrowRight
} from 'lucide-react';

interface ItemTranslation {
  id: string;
  language: Language;
  title: string;
  description: string | null;
}

interface PortfolioItem {
  id: string;
  beforeImage: string;
  afterImage: string;
  category: string;
  isFeatured: boolean;
  isActive: boolean;
  order: number;
  createdAt: string;
  translations: ItemTranslation[];
}

interface PortfolioClientProps {
  initialItems: PortfolioItem[];
}

export default function PortfolioClient({ initialItems }: PortfolioClientProps) {
  const [items, setItems] = useState<PortfolioItem[]>(initialItems);
  const [searchTerm, setSearchTerm] = useState<string>('');
  
  // Modal durumlar─▒
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [editingItem, setEditingItem] = useState<PortfolioItem | null>(null);
  
  // Form inputlar─▒
  const [selectedLanguage, setSelectedLanguage] = useState<Language>('TR');
  const [beforeImage, setBeforeImage] = useState<string>('');
  const [afterImage, setAfterImage] = useState<string>('');
  const [category, setCategory] = useState<string>('T─▒rnak');
  const [isFeatured, setIsFeatured] = useState<boolean>(false);
  const [isActive, setIsActive] = useState<boolean>(true);
  const [order, setOrder] = useState<string>('0');
  
  const [title, setTitle] = useState<string>('');
  const [description, setDescription] = useState<string>('');

  const [formLoading, setFormLoading] = useState<boolean>(false);
  const [loadingId, setLoadingId] = useState<string | null>(null);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const showFeedback = (type: 'success' | 'error', text: string) => {
    setMessage({ type, text });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleOpenCreateModal = () => {
    setEditingItem(null);
    setSelectedLanguage('TR');
    setBeforeImage('');
    setAfterImage('');
    setCategory('T─▒rnak');
    setIsFeatured(false);
    setIsActive(true);
    setOrder('0');
    setTitle('');
    setDescription('');
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (item: PortfolioItem, lang: Language) => {
    setEditingItem(item);
    setSelectedLanguage(lang);
    
    // Se├ğili dilde ├ğeviri var m─▒ kontrol et
    const translation = item.translations.find(t => t.language === lang);

    if (translation) {
      setTitle(translation.title);
      setDescription(translation.description || '');
    } else {
      setTitle('');
      setDescription('');
    }
    
    setBeforeImage(item.beforeImage);
    setAfterImage(item.afterImage);
    setCategory(item.category);
    setIsFeatured(item.isFeatured);
    setIsActive(item.isActive);
    setOrder(item.order.toString());
    setIsModalOpen(true);
  };

  const handleLanguageChangeInForm = (newLang: Language) => {
    if (!editingItem) {
      setSelectedLanguage(newLang);
      return;
    }

    setSelectedLanguage(newLang);
    const translation = editingItem.translations.find(t => t.language === newLang);
    if (translation) {
      setTitle(translation.title);
      setDescription(translation.description || '');
    } else {
      setTitle('');
      setDescription('');
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormLoading(true);

    const formData = new FormData();
    formData.append('beforeImage', beforeImage);
    formData.append('afterImage', afterImage);
    formData.append('category', category);
    formData.append('isFeatured', isFeatured.toString());
    formData.append('isActive', isActive.toString());
    formData.append('order', order);
    formData.append('language', selectedLanguage);
    formData.append('title', title);
    formData.append('description', description);

    let result;
    if (editingItem) {
      const translation = editingItem.translations.find(t => t.language === selectedLanguage);
      result = await updatePortfolioItem(editingItem.id, translation?.id || null, formData);
    } else {
      result = await createPortfolioItem(formData);
    }

    setFormLoading(false);

    if (result.success) {
      window.location.reload();
    } else {
      showFeedback('error', result.error || '─░┼şlem ba┼şar─▒s─▒z oldu.');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Bu ├ğal─▒┼şmay─▒ pasifle┼ştirmek (soft delete) istedi─şinize emin misiniz?')) return;
    setLoadingId(id);
    const result = await deletePortfolioItem(id);
    setLoadingId(null);

    if (result.success) {
      setItems(prev => prev.map(p => p.id === id ? { ...p, isActive: false } : p));
      showFeedback('success', '├çal─▒┼şma pasifle┼ştirildi.');
    } else {
      showFeedback('error', result.error || '─░┼şlem ba┼şar─▒s─▒z oldu.');
    }
  };

  const filteredItems = items.filter(item => 
    item.translations.some(t => t.title.toLowerCase().includes(searchTerm.toLowerCase())) ||
    item.category.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      {/* Feedback Message */}
      {message && (
        <div className={`fixed top-4 right-4 z-50 flex items-center gap-2 px-4 py-3 rounded-xl shadow-lg border transition-all duration-300 ${
          message.type === 'success' ? 'bg-green-50 text-green-800 border-green-200' : 'bg-red-50 text-red-800 border-red-200'
        }`}>
          {message.type === 'success' ? <CheckCircle size={18} /> : <AlertCircle size={18} />}
          <span className="text-sm font-medium">{message.text}</span>
        </div>
      )}

      {/* ├£st ─░┼şlem ├çubu─şu */}
      <div className="bg-white border border-gray-200 rounded-2xl p-4 shadow-sm flex flex-col sm:flex-row gap-4 items-center justify-between">
        <div className="w-full sm:w-80 relative">
          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input
            type="text"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            placeholder="Ba┼şl─▒k veya kategori ile ara..."
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
          />
        </div>
        <button
          onClick={handleOpenCreateModal}
          className="w-full sm:w-auto bg-[var(--color-rose-600)] text-white px-5 py-2 rounded-xl hover:bg-[var(--color-rose-700)] text-sm font-semibold shadow-sm transition-colors flex items-center justify-center gap-2"
        >
          <Plus size={16} />
          Yeni ├çal─▒┼şma Ekle
        </button>
      </div>

      {/* Portf├Ây Kartlar─▒ */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredItems.length === 0 ? (
          <div className="bg-white border border-gray-100 rounded-2xl p-12 text-center col-span-full">
            <ImageIcon className="mx-auto text-gray-300 mb-4" size={48} />
            <p className="text-gray-500 font-medium">Kay─▒tl─▒ portf├Ây ├Â─şesi bulunamad─▒.</p>
          </div>
        ) : (
          filteredItems.map((item) => (
            <div key={item.id} className="bg-white border border-gray-200 rounded-2xl shadow-sm hover:shadow-md transition-shadow duration-200 overflow-hidden flex flex-col justify-between">
              {/* Resimler (Before / After Kar┼ş─▒la┼şt─▒rmal─▒ yan yana) */}
              <div className="grid grid-cols-2 h-40 bg-gray-50 border-b border-gray-100 relative">
                <div className="relative overflow-hidden h-full">
                  <Image width={800} height={800} src={item.beforeImage} alt="├ûncesi" className="w-full h-full object-cover" />
                  <span className="absolute bottom-2 left-2 bg-black/60 text-white text-[10px] font-bold px-1.5 py-0.5 rounded">
                    ├ûncesi
                  </span>
                </div>
                <div className="relative overflow-hidden h-full border-l border-white">
                  <Image width={800} height={800} src={item.afterImage} alt="Sonras─▒" className="w-full h-full object-cover" />
                  <span className="absolute bottom-2 right-2 bg-[var(--color-rose-600)]/80 text-white text-[10px] font-bold px-1.5 py-0.5 rounded">
                    Sonras─▒
                  </span>
                </div>
                {item.isFeatured && (
                  <span className="absolute top-2 left-2 bg-yellow-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded shadow">
                    ├ûne ├ç─▒kan
                  </span>
                )}
              </div>

              {/* Detaylar */}
              <div className="p-5 flex-1 flex flex-col justify-between gap-4">
                <div className="space-y-2">
                  <div className="flex justify-between items-start">
                    <h3 className="font-bold text-gray-900 line-clamp-1">
                      {item.translations.find(t => t.language === 'TR')?.title || item.translations[0]?.title || 'Ba┼şl─▒ks─▒z'}
                    </h3>
                    <span className="text-[10px] bg-gray-100 border border-gray-200 text-gray-600 px-2 py-0.5 rounded font-bold">
                      {item.category}
                    </span>
                  </div>
                  <p className="text-xs text-gray-500 line-clamp-2">
                    {item.translations.find(t => t.language === 'TR')?.description || item.translations[0]?.description || 'A├ğ─▒klama girilmemi┼ş.'}
                  </p>
                </div>

                {/* Diller ve Rotalar */}
                <div className="space-y-2 border-t border-gray-50 pt-3">
                  <div className="flex justify-between items-center text-[10px] text-gray-400 font-bold uppercase tracking-wider">
                    <span>├çeviriler</span>
                    <span>S─▒ra: {item.order}</span>
                  </div>
                  <div className="flex flex-wrap gap-1">
                    {['TR', 'EN', 'RU', 'DE'].map((lang) => {
                      const t = item.translations.find(tr => tr.language === lang);
                      return t ? (
                        <button
                          key={lang}
                          onClick={() => handleOpenEditModal(item, lang as Language)}
                          className="text-[10px] font-bold bg-rose-50 border border-rose-100 text-[var(--color-rose-700)] px-2 py-0.5 rounded hover:bg-rose-100 transition-colors"
                        >
                          {lang}
                        </button>
                      ) : (
                        <button
                          key={lang}
                          onClick={() => handleOpenEditModal(item, lang as Language)}
                          className="text-[10px] font-semibold border border-dashed border-gray-200 text-gray-400 px-2 py-0.5 rounded hover:border-rose-300 hover:text-[var(--color-rose-600)] transition-colors"
                        >
                          + {lang}
                        </button>
                      );
                    })}
                  </div>
                </div>

                {/* ─░┼şlemler */}
                <div className="flex gap-2 pt-3 border-t border-gray-100 justify-between items-center">
                  <span className={`inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full font-bold border ${
                    item.isActive
                      ? 'bg-green-50 text-green-700 border-green-200' 
                      : 'bg-red-50 text-red-700 border-red-200'
                  }`}>
                    {item.isActive ? 'Aktif' : 'Pasif'}
                  </span>
                  <div className="flex gap-1.5">
                    <button
                      onClick={() => handleOpenEditModal(item, 'TR')}
                      className="p-1.5 border border-gray-200 rounded-lg text-gray-600 hover:bg-gray-50 transition-colors"
                      title="D├╝zenle"
                    >
                      <Edit size={14} />
                    </button>
                    <button
                      onClick={() => handleDelete(item.id)}
                      disabled={loadingId === item.id}
                      className="p-1.5 border border-red-200 rounded-lg text-red-600 hover:bg-red-50 transition-colors"
                      title="Pasifle┼ştir"
                    >
                      <Trash2 size={14} />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm transition-all duration-300">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-200 max-h-[90vh] flex flex-col">
            {/* Header */}
            <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 shrink-0">
              <h3 className="text-base font-bold text-gray-900">
                {editingItem ? '├çal─▒┼şmay─▒ D├╝zenle' : 'Yeni ├çal─▒┼şma Ekle'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 transition-colors">
                <X size={18} />
              </button>
            </div>

            {/* Form */}
            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-6 space-y-4">
              {/* Dil Se├ğimi */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">├çeviri Dili</label>
                <div className="flex gap-2">
                  {['TR', 'EN', 'RU', 'DE'].map((lang) => (
                    <button
                      key={lang}
                      type="button"
                      onClick={() => handleLanguageChangeInForm(lang as Language)}
                      className={`px-3 py-1.5 text-xs font-bold rounded-lg border transition-all ${
                        selectedLanguage === lang
                          ? 'bg-[var(--color-rose-600)] text-white border-[var(--color-rose-600)]'
                          : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                      }`}
                    >
                      {lang}
                    </button>
                  ))}
                </div>
              </div>

              {/* Ba┼şl─▒k */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">─░┼şlem / ├çal─▒┼şma Ba┼şl─▒─ş─▒</label>
                <input
                  type="text"
                  required
                  value={title}
                  onChange={(e) => setTitle(e.target.value)}
                  placeholder="├ûrn: G├╝l Kurusu Protez T─▒rnak Uygulamas─▒"
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white"
                />
              </div>

              {/* A├ğ─▒klama */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">A├ğ─▒klama (Opsiyonel)</label>
                <textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  placeholder="─░┼şlem detaylar─▒, kullan─▒lan malzemeler..."
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white h-16 resize-none"
                />
              </div>

              {/* ├ûncesi & Sonras─▒ G├Ârselleri */}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">├ûncesi G├Ârsel (Before)</label>
                  <input
                    type="text"
                    required
                    value={beforeImage}
                    onChange={(e) => setBeforeImage(e.target.value)}
                    placeholder="/uploads/before.jpg"
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-xs focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white font-mono"
                  />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Sonras─▒ G├Ârsel (After)</label>
                  <input
                    type="text"
                    required
                    value={afterImage}
                    onChange={(e) => setAfterImage(e.target.value)}
                    placeholder="/uploads/after.jpg"
                    className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-xs focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white font-mono"
                  />
                </div>
              </div>

              {/* Kategori & S─▒ralama */}
              <div className="grid grid-cols-2 gap-4">
                <div>
