                    className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white font-mono"
                  />
                </div>
              </div>

              {/* YouTube */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">YouTube URL</label>
                <div className="relative">
                  <Play className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                  <input
                    type="url"
                    value={youtubeUrl}
                    onChange={(e) => setYoutubeUrl(e.target.value)}
                    placeholder="https://youtube.com/nailslashesstudio"
                    className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white font-mono"
                  />
                </div>
              </div>

              {/* Telegram */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Telegram URL</label>
                <div className="relative">
                  <LinkIcon className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                  <input
                    type="url"
                    value={telegramUrl}
                    onChange={(e) => setTelegramUrl(e.target.value)}
                    placeholder="https://t.me/nailslashesstudio"
                    className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white font-mono"
                  />
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'system' && (
          <div className="space-y-4">
            <h3 className="text-sm font-bold text-gray-800 border-b border-gray-100 pb-2 flex items-center gap-2">
              <Clock size={16} className="text-[var(--color-rose-600)]" />
              Sistem ve Rezervasyon Kurallar─▒
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Rezervasyon Aral─▒─ş─▒ */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Takvim Zaman Dilimi (Aral─▒k)</label>
                <select
                  value={bookingInterval}
                  onChange={(e) => setBookingInterval(e.target.value)}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
                >
                  <option value="15">15 Dakika</option>
                  <option value="30">30 Dakika</option>
                  <option value="45">45 Dakika</option>
                  <option value="60">60 Dakika</option>
                </select>
              </div>

              {/* Para Birimi */}
              <div>
                <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Para Birimi</label>
                <select
                  value={currency}
                  onChange={(e) => setCurrency(e.target.value)}
                  className="w-full px-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)]"
                >
                  <option value="TL">T├╝rk Liras─▒ (TL)</option>
                  <option value="USD">Amerikan Dolar─▒ (USD)</option>
                  <option value="EUR">Euro (EUR)</option>
                </select>
              </div>
            </div>

            {/* Google Yorum ─░stek Linki */}
            <div>
              <label className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-1">Google ─░┼şletme Yorum ─░stek Linki (Review Link)</label>
              <div className="relative">
                <Star className="absolute left-3.5 top-1/2 -translate-y-1/2 text-gray-400" size={14} />
                <input
                  type="url"
                  value={googleReviewsLink}
                  onChange={(e) => setGoogleReviewsLink(e.target.value)}
                  placeholder="https://g.page/r/YOUR_BUSINESS_ID/review"
                  className="w-full pl-9 pr-4 py-2 bg-gray-50 border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-[var(--color-rose-500)] focus:bg-white font-mono"
                />
              </div>
            </div>
          </div>
        )}

        {/* Submit */}
        <div className="flex justify-end pt-4 border-t border-gray-100">
          <button
            type="submit"
            disabled={loading}
            className="bg-[var(--color-rose-600)] text-white px-6 py-2.5 rounded-xl hover:bg-[var(--color-rose-700)] text-sm font-semibold shadow-sm transition-colors disabled:opacity-50 flex items-center gap-2"
          >
            {loading ? 'Kaydediliyor...' : 'Ayarlar─▒ Kaydet'}
          </button>
        </div>
      </form>
    </div>
  );
}

"use client";

import Image from 'next/image';
import { useState } from 'react';
import { 
  Plus, 
  Edit, 
  Trash2, 
  Clock, 
  Calendar, 
  Check, 
  X, 
  UserPlus, 
  Award, 
  MapPin, 
  DollarSign,
  ToggleLeft,
  ToggleRight,
  Loader2
} from 'lucide-react';
import { 
  createStaff, 
  updateStaff, 
  deleteStaff, 
  updateStaffWorkingHours, 
  addStaffLeave, 
  deleteStaffLeave 
} from '@/app/actions/staff';

type LocationOption = {
  id: string;
  name: string;
};

type ServiceOption = {
  id: string;
  name: string;
  duration: number;
  price: string;
};

type WorkingHoursItem = {
  id?: string;
  dayOfWeek: number;
  openTime: string;
  closeTime: string;
  isClosed: boolean;
  breakStart?: string | null;
  breakEnd?: string | null;
};

type LeaveItem = {
  id: string;
  date: string;
  isFullDay: boolean;
  startTime?: string | null;
  endTime?: string | null;
};

type StaffMember = {
  id: string;
  name: string;
  image?: string | null;
  specialty?: string | null;
  isActive: boolean;
  locationId?: string | null;
  locationName: string;
  commissionRate: number;
  serviceIds: string[];
  workingHours: WorkingHoursItem[];
  leaves: LeaveItem[];
};

type StaffClientProps = {
  initialStaff: StaffMember[];
  locations: LocationOption[];
  services: ServiceOption[];
  };

const DAY_NAMES = ['Pazar', 'Pazartesi', 'Sal─▒', '├çar┼şamba', 'Per┼şembe', 'Cuma', 'Cumartesi'];

export default function StaffClient({ initialStaff, locations, services }: StaffClientProps) {
  const [staffList, setStaffList] = useState<StaffMember[]>(initialStaff);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Modallerin durumlar─▒
  const [activeModal, setActiveModal] = useState<'create' | 'edit' | 'workingHours' | 'leaves' | null>(null);
  const [selectedStaff, setSelectedStaff] = useState<StaffMember | null>(null);

  // Form De─şi┼şkenleri (Create / Edit)
  const [name, setName] = useState('');
  const [image, setImage] = useState('');
  const [specialty, setSpecialty] = useState('');
  const [locationId, setLocationId] = useState('');
  const [commissionRate, setCommissionRate] = useState(0);
  const [selectedServiceIds, setSelectedServiceIds] = useState<string[]>([]);
  const [isActive, setIsActive] = useState(true);

  // ├çal─▒┼şma Saatleri De─şi┼şkenleri
  const [workingHoursList, setWorkingHoursList] = useState<WorkingHoursItem[]>([]);

  // ─░zin De─şi┼şkenleri
  const [leaveDate, setLeaveDate] = useState('');
  const [leaveIsFullDay, setLeaveIsFullDay] = useState(true);
  const [leaveStartTime, setLeaveStartTime] = useState('09:00');
  const [leaveEndTime, setLeaveEndTime] = useState('18:00');

  const openCreateModal = () => {
    setName('');
    setImage('');
    setSpecialty('');
    setLocationId(locations[0]?.id || '');
    setCommissionRate(0);
    setSelectedServiceIds([]);
    setIsActive(true);
    setActiveModal('create');
  };

  const openEditModal = (staff: StaffMember) => {
    setSelectedStaff(staff);
    setName(staff.name);
    setImage(staff.image || '');
    setSpecialty(staff.specialty || '');
    setLocationId(staff.locationId || '');
    setCommissionRate(staff.commissionRate);
    setSelectedServiceIds(staff.serviceIds);
    setIsActive(staff.isActive);
    setActiveModal('edit');
  };

  const openWorkingHoursModal = (staff: StaffMember) => {
    setSelectedStaff(staff);
    // 7 g├╝n├╝n de listede oldu─şundan emin olal─▒m
    const hours = [...staff.workingHours];
    for (let day = 0; day <= 6; day++) {
      if (!hours.some(h => h.dayOfWeek === day)) {
        hours.push({
          dayOfWeek: day,
          openTime: '09:00',
          closeTime: '19:00',
          isClosed: day === 0,
          breakStart: '13:00',
          breakEnd: '14:00'
        });
      }
    }
    const sortedHours = hours.sort((a, b) => a.dayOfWeek - b.dayOfWeek);
    setWorkingHoursList(JSON.parse(JSON.stringify(sortedHours)));
    setActiveModal('workingHours');
  };

  const openLeavesModal = (staff: StaffMember) => {
    setSelectedStaff(staff);
    setLeaveDate('');
    setLeaveIsFullDay(true);
    setLeaveStartTime('09:00');
    setLeaveEndTime('18:00');
    setActiveModal('leaves');
  };

  // Personel Kaydet (Create)
  const handleCreateSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const result = await createStaff({
      name,
      image: image || undefined,
      specialty: specialty || undefined,
      locationId: locationId || undefined,
      commissionRate,
      serviceIds: selectedServiceIds
    });

    setIsSubmitting(false);

    if (result.success && result.data) {
      // Listeyi g├╝ncelle (yeni ├ğal─▒┼şana bo┼ş ├ğal─▒┼şma saatleri ve izinler ekleyelim)
      const newStaff: StaffMember = {
        ...result.data,
        locationName: locations.find(l => l.id === locationId)?.name || '┼Şube Atanmam─▒┼ş',
        commissionRate: Number(result.data.commissionRate || 0),
        serviceIds: selectedServiceIds,
        workingHours: [],
        leaves: []
      };
      setStaffList(prev => [...prev, newStaff].sort((a, b) => a.name.localeCompare(b.name)));
      setActiveModal(null);
      // Sayfay─▒ revalidate etmesi i├ğin reload edelim ki tam verileri prisma ili┼şkileriyle ├ğeksin
      window.location.reload();
    } else {
      alert(result.error || 'Personel eklenirken hata olu┼ştu.');
    }
  };

  // Personel G├╝ncelle (Edit)
  const handleEditSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStaff) return;
    setIsSubmitting(true);

    const result = await updateStaff(selectedStaff.id, {
      name,
      image: image || undefined,
      specialty: specialty || undefined,
      locationId: locationId || undefined,
      commissionRate,
      isActive,
      serviceIds: selectedServiceIds
    });

    setIsSubmitting(false);

    if (result.success && result.data) {
      setStaffList(prev => prev.map(st => {
        if (st.id === selectedStaff.id) {
          return {
            ...st,
            name,
            image,
            specialty,
            locationId,
            locationName: locations.find(l => l.id === locationId)?.name || '┼Şube Atanmam─▒┼ş',
            commissionRate,
            isActive,
            serviceIds: selectedServiceIds
          };
        }
        return st;
      }));
      setActiveModal(null);
    } else {
      alert(result.error || 'Personel g├╝ncellenirken hata olu┼ştu.');
    }
  };

  // Personel Sil (Soft Delete)
  const handleDelete = async (id: string, name: string) => {
    if (!confirm(`${name} isimli personeli pasife almak ve listeden kald─▒rmak istedi─şinize emin misiniz?`)) return;

    const result = await deleteStaff(id);
    if (result.success) {
      setStaffList(prev => prev.filter(st => st.id !== id));
    } else {
      alert(result.error || 'Personel silinirken hata olu┼ştu.');
    }
  };

  // ├çal─▒┼şma Saatleri Kaydet
  const handleWorkingHoursSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStaff) return;
    setIsSubmitting(true);

    const result = await updateStaffWorkingHours(selectedStaff.id, workingHoursList);
    setIsSubmitting(false);

    if (result.success) {
      // Saatleri g├╝ncelle
      setStaffList(prev => prev.map(st => {
        if (st.id === selectedStaff.id) {
          return { ...st, workingHours: workingHoursList };
        }
        return st;
      }));
      setActiveModal(null);
      window.location.reload(); // Prisma id'leri yenilendi─şi i├ğin reload en g├╝venlisi
    } else {
      alert(result.error || '├çal─▒┼şma saatleri g├╝ncellenirken hata olu┼ştu.');
    }
  };

  // ─░zin Ekle
  const handleAddLeave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedStaff || !leaveDate) return;
    setIsSubmitting(true);

    const result = await addStaffLeave(selectedStaff.id, {
      date: new Date(leaveDate),
      isFullDay: leaveIsFullDay,
      startTime: leaveIsFullDay ? undefined : leaveStartTime,
      endTime: leaveIsFullDay ? undefined : leaveEndTime
    });

    setIsSubmitting(false);

    if (result.success && result.data) {
      const newLeave: LeaveItem = {
        id: result.data.id,
        date: leaveDate,
        isFullDay: leaveIsFullDay,
        startTime: leaveIsFullDay ? null : leaveStartTime,
        endTime: leaveIsFullDay ? null : leaveEndTime
      };

      setStaffList(prev => prev.map(st => {
        if (st.id === selectedStaff.id) {
          return { ...st, leaves: [...st.leaves, newLeave].sort((a, b) => a.date.localeCompare(b.date)) };
        }
        return st;
      }));

      // Se├ğilen ├ğal─▒┼şan─▒n izinlerini de g├╝ncelle
      setSelectedStaff(prev => {
        if (!prev) return null;
        return { ...prev, leaves: [...prev.leaves, newLeave].sort((a, b) => a.date.localeCompare(b.date)) };
      });

      setLeaveDate('');
    } else {
      alert(result.error || '─░zin eklenirken hata olu┼ştu.');
    }
  };

  // ─░zin Sil
  const handleDeleteLeave = async (leaveId: string) => {
    if (!confirm('Bu izin kayd─▒n─▒ silmek istedi─şinize emin misiniz?')) return;
    if (!selectedStaff) return;

    setIsSubmitting(true);
    const result = await deleteStaffLeave(leaveId);
    setIsSubmitting(false);

    if (result.success) {
      setStaffList(prev => prev.map(st => {
        if (st.id === selectedStaff.id) {
          return { ...st, leaves: st.leaves.filter(l => l.id !== leaveId) };
        }
        return st;
      }));

      setSelectedStaff(prev => {
        if (!prev) return null;
        return { ...prev, leaves: prev.leaves.filter(l => l.id !== leaveId) };
      });
    } else {
      alert(result.error || '─░zin silinirken hata olu┼ştu.');
    }
  };

  const handleServiceToggle = (serviceId: string) => {
    setSelectedServiceIds(prev => 
      prev.includes(serviceId)
        ? prev.filter(id => id !== serviceId)
        : [...prev, serviceId]
    );
  };

  return (
    <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm relative">
      <div className="flex justify-between items-center mb-6">
        <h3 className="text-lg font-bold text-gray-800">Aktif ├çal─▒┼şanlar ({staffList.length})</h3>
        <button
          onClick={openCreateModal}
          className="flex items-center gap-2 px-4 py-2 bg-[var(--color-rose-600)] text-white font-medium rounded-xl hover:bg-[var(--color-rose-700)] transition-all shadow-sm text-sm"
        >
          <Plus size={16} />
          Yeni Personel Ekle
        </button>
      </div>

      {staffList.length === 0 ? (
        <div className="text-center py-12 text-gray-500 border border-dashed border-gray-200 rounded-2xl">
          <UserPlus size={40} className="mx-auto text-gray-300 mb-3" />
          <p className="font-medium">Kay─▒tl─▒ personel bulunamad─▒.</p>
          <p className="text-xs text-gray-400 mt-1">Sisteme ilk ├ğal─▒┼şan─▒ ekleyerek randevu almaya haz─▒r hale getirin.</p>
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-gray-100 text-gray-400 text-xs font-semibold uppercase tracking-wider">
                <th className="py-4 px-4">Uzman / Personel</th>
                <th className="py-4 px-4">┼Şube</th>
                <th className="py-4 px-4">Komisyon (%)</th>
                <th className="py-4 px-4">Hizmet Say─▒s─▒</th>
                <th className="py-4 px-4">Durum</th>
                <th className="py-4 px-4 text-right">─░┼şlemler</th>
              </tr>
            </thead>
