                    <p className="text-[9px] text-white truncate font-medium">
                      {item.fileName || 'Ads─▒z'}
                    </p>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 py-3 border-t border-gray-100 flex justify-between items-center bg-gray-50 shrink-0">
          <div className="text-xs text-gray-500">
