};

type Props = {
  images: GalleryImageItem[];
  categories: GalleryCategory[];
  locale: string;
};

export default function GalleryClient({ images, categories, locale }: Props) {
  const [selectedImage, setSelectedImage] = useState<GalleryImageItem | null>(null);
