  // "T├╝m├╝" etiketi dil bazl─▒
  const allLabel = locale === 'tr' ? 'T├╝m├╝' : locale === 'de' ? 'Alle' : locale === 'ru' ? 'ºÆªüºÁ' : 'All';
  const noImageLabel = locale === 'tr' ? 'G├Ârsel Bulunamad─▒' : locale === 'de' ? 'Kein Bild gefunden' : locale === 'ru' ? 'ºİºÀº¥º▒ªÇº░ºÂºÁº¢º©ºÁ º¢ºÁ º¢º░º╣º┤ºÁº¢º¥' : 'No images found';
  const noImageDesc = locale === 'tr' ? 'Bu kategoriye ait uygulama g├Ârseli hen├╝z y├╝klenmemi┼ş.' : locale === 'de' ? 'F├╝r diese Kategorie wurden noch keine Bilder hochgeladen.' : locale === 'ru' ? 'ºöº╗ªÅ ªıªéº¥º╣ º║º░ªéºÁº│º¥ªÇº©º© º┐º¥º║º░ º¢ºÁ ºÀº░º│ªÇªâºÂºÁº¢ªï º©ºÀº¥º▒ªÇº░ºÂºÁº¢º©ªÅ.' : 'No images have been uploaded for this category yet.';

  const getFilteredImages = () => {
    if (activeFilter === 'all') return images;
    return images.filter(img => img.categoryId === activeFilter);
  };

  const filtered = getFilteredImages();

  return (
    <div className="space-y-12">
      {/* Kategori Filtreleri ÔÇö DB'den gelen dinamik veriler */}
      {categories.length > 0 && (
        <div className="flex flex-wrap justify-center gap-3">
          <button
            onClick={() => setActiveFilter('all')}
