import crypto from 'crypto';

// 32 karakterlik bir gizli anahtar (├ğevre de─şi┼şkeninde yoksa fallback olarak kullan─▒l─▒r)
const ENCRYPTION_KEY = process.env.AUTH_SECRET || "c5d8f41c683917d194baa764f9642606"; 
const IV_LENGTH = 16;

/**
 * ┼Şifreyi PBKDF2 algoritmas─▒ ve rastgele salt ile g├╝venli bir ┼şekilde hash'ler.
 */
export function hashPassword(password: string): string {
  const salt = crypto.randomBytes(16).toString('hex');
  const hash = crypto.pbkdf2Sync(password, salt, 10000, 64, 'sha512').toString('hex');
  return `${salt}:${hash}`;
}

/**
 * Girilen ┼şifreyi kaydedilen hash ile kar┼ş─▒la┼şt─▒r─▒r.
 */
export function verifyPassword(password: string, storedHash: string): boolean {
  try {
    const [salt, hash] = storedHash.split(':');
    if (!salt || !hash) return false;
    const verifyHash = crypto.pbkdf2Sync(password, salt, 10000, 64, 'sha512').toString('hex');
    return hash === verifyHash;
  } catch (error) {
    return false;
  }
}

/**
 * Oturum verisini AES-256-CBC ile ┼şifreler.
 */
export function encryptSession(data: any): string {
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv('aes-256-cbc', Buffer.from(ENCRYPTION_KEY.substring(0, 32)), iv);
  let encrypted = cipher.update(JSON.stringify(data));
  encrypted = Buffer.concat([encrypted, cipher.final()]);
  return iv.toString('hex') + ':' + encrypted.toString('hex');
}

/**
 * ┼Şifrelenmi┼ş oturum verisini ├ğ├Âzer ve objeye d├Ân├╝┼şt├╝r├╝r.
 */
export function decryptSession(text: string): any | null {
  try {
    const textParts = text.split(':');
    const iv = Buffer.from(textParts.shift() || '', 'hex');
    const encryptedText = Buffer.from(textParts.join(':'), 'hex');
    const decipher = crypto.createDecipheriv('aes-256-cbc', Buffer.from(ENCRYPTION_KEY.substring(0, 32)), iv);
    let decrypted = decipher.update(encryptedText);
    decrypted = Buffer.concat([decrypted, decipher.final()]);
    return JSON.parse(decrypted.toString());
  } catch (error) {
    return null;
  }
}

import nodemailer from 'nodemailer';
import { prisma } from '@/lib/prisma';

const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_PASS,
  },
});

// ┼Şablon de─şi┼şkenlerini de─şi┼ştiren yard─▒mc─▒ fonksiyon
function replaceVariables(
  template: string, 
  vars: Record<string, string>
): string {
  let result = template;
  for (const [key, value] of Object.entries(vars)) {
    result = result.replace(new RegExp(`\\{\\{${key}\\}\\}`, 'g'), value);
  }
  return result;
}

export const sendBookingEmail = async (
  to: string, 
  customerName: string, 
  serviceName: string, 
  date: Date, 
  time: string,
  customerLanguage: string = 'TR'
) => {
  const lang = customerLanguage.toUpperCase();
  const localeMap: Record<string, string> = {
    TR: 'tr-TR',
    EN: 'en-US',
    RU: 'ru-RU',
    DE: 'de-DE'
  };
  const formatLocale = localeMap[lang] || 'tr-TR';

  const formattedDate = date.toLocaleDateString(formatLocale, {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  const vars = {
    customerName,
    serviceName,
    date: formattedDate,
    time,
    customerEmail: to,
  };

  try {
    // Veritaban─▒ndan birle┼şik ┼şablonlar─▒ ├ğek
    const customerTemplate = await prisma.emailTemplate.findUnique({
      where: { key: 'booking_received' },
    });

    const adminTemplate = await prisma.emailTemplate.findUnique({
      where: { key: 'booking_admin_notification' },
    });

    // M├╝┼şteri e-postas─▒
    if (customerTemplate && customerTemplate.isActive) {
      let subject = customerTemplate.subject;
      let html = customerTemplate.body;

      try {
        const parsedSubject = JSON.parse(customerTemplate.subject);
        const parsedBody = JSON.parse(customerTemplate.body);
        subject = parsedSubject[lang] || parsedSubject['TR'] || customerTemplate.subject;
        html = parsedBody[lang] || parsedBody['TR'] || customerTemplate.body;
      } catch (e) {
        // JSON format─▒nda de─şilse do─şrudan kullan─▒l─▒r
      }

      const finalSubject = replaceVariables(subject, vars);
      const finalHtml = replaceVariables(html, vars);

      await transporter.sendMail({
         from: `"Nails & Lashes Studio" <${process.env.EMAIL_USER}>`,
         to: to,
         subject: finalSubject,
         html: finalHtml,
      });
    } else {
      console.log(`M├╝┼şteri ┼şablonu bulunamad─▒ veya pasif: booking_received`);
    }

    // Admin e-postas─▒
    if (adminTemplate && adminTemplate.isActive) {
      const subject = replaceVariables(adminTemplate.subject, vars);
      const html = replaceVariables(adminTemplate.body, vars);

      await transporter.sendMail({
        from: `"Sistem Bildirimi" <${process.env.EMAIL_USER}>`,
        to: process.env.EMAIL_USER!,
        subject,
        html,
      });
    }

    return { success: true };
  } catch (error) {
    console.error("E-posta g├Ânderme hatas─▒:", error);
    return { success: false };
  }
};

